package com.tradepulseai.stockservice.service;

import com.tradepulseai.stockservice.model.Stock;
import com.tradepulseai.stockservice.model.StockMarketData;
import com.tradepulseai.stockservice.repository.StockMarketDataRepository;
import com.tradepulseai.stockservice.repository.StockRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;
import org.springframework.web.client.RestClient;
import org.springframework.web.util.UriComponentsBuilder;
import tools.jackson.databind.JsonNode;

import java.math.BigDecimal;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;

@Service
public class NewsService {

    private static final Logger log = LoggerFactory.getLogger(NewsService.class);

    private final RestClient restClient;
    private final StockMarketDataRepository stockMarketDataRepository;
    private final String apiKey;
    private final String apiBaseUrl;
    private final boolean newsIntegrationEnabled;

    public NewsService(
            @Value("${massive.api.base-url}") String apiBaseUrl,
            @Value("${massive.api.key:}") String apiKey,
            @Value("${massive.news.integration-enabled:false}") boolean newsIntegrationEnabled,
            StockMarketDataRepository stockMarketDataRepository) {
        this.restClient = RestClient.create();
        this.stockMarketDataRepository = stockMarketDataRepository;
        this.apiKey = apiKey;
        this.apiBaseUrl = apiBaseUrl;
        this.newsIntegrationEnabled = newsIntegrationEnabled;
    }

    /**
     * Fetch daily news for a stock and update sentiment data
     */
    public void fetchAndUpdateNewsSentiment(Stock stock, LocalDate tradingDate) {
        if (!newsIntegrationEnabled || apiKey == null || apiKey.isBlank()) {
            log.debug("News integration disabled or API key not configured");
            return;
        }

        try {
            Optional<StockMarketData> marketDataOpt =
                stockMarketDataRepository.findByStockAndTradingDate(stock, tradingDate);

            if (marketDataOpt.isEmpty()) {
                log.debug("No market data found for stock {} on {}", stock.getSymbol(), tradingDate);
                return;
            }

            StockMarketData marketData = marketDataOpt.get();

            // Fetch news for this stock
            List<NewsArticle> articles = fetchNewsForStock(stock.getSymbol(), tradingDate);

            if (articles.isEmpty()) {
                log.debug("No news found for {} on {}", stock.getSymbol(), tradingDate);
                marketData.setNewsCount(0);
                marketData.setSentimentScore(BigDecimal.ZERO);
                stockMarketDataRepository.save(marketData);
                return;
            }

            // Aggregate sentiment
            SentimentAggregation sentiment = aggregateSentiment(articles);

            marketData.setNewsCount(articles.size());
            marketData.setSentimentScore(new BigDecimal(sentiment.score).setScale(4, java.math.RoundingMode.HALF_UP));

            stockMarketDataRepository.save(marketData);
            log.info("Updated sentiment for {} on {} (score: {})",
                stock.getSymbol(), tradingDate, sentiment.score);

        } catch (Exception e) {
            log.error("Error fetching news for {} on {}", stock.getSymbol(), tradingDate, e);
        }
    }

    private List<NewsArticle> fetchNewsForStock(String ticker, LocalDate date) {
        List<NewsArticle> articles = new ArrayList<>();

        try {
            LocalDate startDate = date;
            LocalDate endDate = date.plusDays(1);

            String url = UriComponentsBuilder
                .fromHttpUrl(apiBaseUrl + "/v2/reference/news")
                .queryParam("ticker", ticker)
                .queryParam("published_utc.gte", startDate.format(DateTimeFormatter.ISO_DATE))
                .queryParam("published_utc.lt", endDate.format(DateTimeFormatter.ISO_DATE))
                .queryParam("limit", 100)
                .queryParam("sort", "published_utc")
                .queryParam("apiKey", apiKey)
                .toUriString();

            String response = restClient.get()
                .uri(url)
                .retrieve()
                .body(String.class);

            if (response == null) {
                return articles;
            }

            JsonNode root = new tools.jackson.databind.ObjectMapper().readTree(response);
            JsonNode results = root.get("results");

            if (results != null && results.isArray()) {
                for (JsonNode result : results) {
                    NewsArticle article = parseNewsArticle(result);
                    if (article != null) {
                        articles.add(article);
                    }
                }
            }

        } catch (Exception e) {
            log.error("Error fetching news from Polygon.io for {}", ticker, e);
        }

        return articles;
    }

    private NewsArticle parseNewsArticle(JsonNode node) {
        try {
            NewsArticle article = new NewsArticle();
            article.title = node.get("title") != null ? node.get("title").asText() : "";
            article.description = node.get("description") != null ? node.get("description").asText() : "";
            article.author = node.get("author") != null ? node.get("author").asText() : "";
            article.url = node.get("article_url") != null ? node.get("article_url").asText() : "";

            // Extract sentiment from insights
            JsonNode insights = node.get("insights");
            if (insights != null && insights.isArray() && insights.size() > 0) {
                JsonNode firstInsight = insights.get(0);
                String sentiment = firstInsight.get("sentiment") != null ?
                    firstInsight.get("sentiment").asText() : "neutral";
                String reasoning = firstInsight.get("sentiment_reasoning") != null ?
                    firstInsight.get("sentiment_reasoning").asText() : "";

                article.sentiment = sentiment;
                article.reasoning = reasoning;
            }

            // Extract publisher
            JsonNode publisher = node.get("publisher");
            if (publisher != null) {
                article.publisher = publisher.get("name") != null ?
                    publisher.get("name").asText() : "Unknown";
            }

            return article;
        } catch (Exception e) {
            log.error("Error parsing news article", e);
            return null;
        }
    }

    private SentimentAggregation aggregateSentiment(List<NewsArticle> articles) {
        SentimentAggregation agg = new SentimentAggregation();

        int positive = 0, negative = 0;

        for (NewsArticle article : articles) {
            if ("positive".equalsIgnoreCase(article.sentiment)) {
                positive++;
            } else if ("negative".equalsIgnoreCase(article.sentiment)) {
                negative++;
            }
        }

        // Calculate composite sentiment score (-1.0 to 1.0)
        int total = articles.size();
        double score = (double)(positive - negative) / total;
        agg.score = score;

        return agg;
    }

    static class NewsArticle {
        String title;
        String description;
        String author;
        String url;
        String sentiment = "neutral";
        String reasoning;
        String publisher = "Unknown";
    }

    static class SentimentAggregation {
        double score;
    }
}

package com.tradepulseai.stockservice.service;

import com.tradepulseai.stockservice.model.Stock;
import com.tradepulseai.stockservice.model.StockMarketData;
import com.tradepulseai.stockservice.repository.StockMarketDataRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.stereotype.Service;
import org.springframework.web.client.RestClient;
import org.springframework.web.util.UriComponentsBuilder;
import tools.jackson.databind.JsonNode;

import java.math.BigDecimal;
import java.time.LocalDate;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.List;
import java.util.Optional;

@Service
public class NewsService {

    private static final Logger log = LoggerFactory.getLogger(NewsService.class);

    private final RestClient restClient;
    private final StockMarketDataRepository stockMarketDataRepository;
    private final String apiKey;
    private final String apiBaseUrl;
    private final boolean newsIntegrationEnabled;

    public NewsService(
            @Value("${massive.api.base-url}") String apiBaseUrl,
            @Value("${massive.api.key:}") String apiKey,
            @Value("${massive.news.integration-enabled:false}") boolean newsIntegrationEnabled,
            StockMarketDataRepository stockMarketDataRepository) {
        this.restClient = RestClient.create();
        this.stockMarketDataRepository = stockMarketDataRepository;
        this.apiKey = apiKey;
        this.apiBaseUrl = apiBaseUrl;
        this.newsIntegrationEnabled = newsIntegrationEnabled;
    }

    /**
     * Fetch daily news for a stock and update sentiment data
     */
    public void fetchAndUpdateNewsSentiment(Stock stock, LocalDate tradingDate) {
        if (!newsIntegrationEnabled || apiKey == null || apiKey.isBlank()) {
            log.debug("News integration disabled or API key not configured");
            return;
        }

        try {
            Optional<StockMarketData> marketDataOpt =
                stockMarketDataRepository.findByStockAndTradingDate(stock, tradingDate);

            if (marketDataOpt.isEmpty()) {
                log.debug("No market data found for stock {} on {}", stock.getSymbol(), tradingDate);
                return;
            }

            StockMarketData marketData = marketDataOpt.get();

            // Fetch news for this stock
            List<NewsArticle> articles = fetchNewsForStock(stock.getSymbol(), tradingDate);

            if (articles.isEmpty()) {
                log.debug("No news found for {} on {}", stock.getSymbol(), tradingDate);
                marketData.setNewsCount(0);
                marketData.setSentimentScore(BigDecimal.ZERO);
                marketData.setDailyNews(null);
                stockMarketDataRepository.save(marketData);
                return;
            }

            // Aggregate sentiment
            SentimentAggregation sentiment = aggregateSentiment(articles);

            marketData.setNewsCount(articles.size());
            marketData.setSentimentScore(new BigDecimal(sentiment.score).setScale(4, java.math.RoundingMode.HALF_UP));
            marketData.setDailyNews(buildDailyNewsSummary(articles));

            stockMarketDataRepository.save(marketData);
            log.info("Updated sentiment for {} on {} (score: {})",
                stock.getSymbol(), tradingDate, sentiment.score);

        } catch (Exception e) {
            log.error("Error fetching news for {} on {}", stock.getSymbol(), tradingDate, e);
        }
    }

    private List<NewsArticle> fetchNewsForStock(String ticker, LocalDate date) {
        List<NewsArticle> articles = new ArrayList<>();

        try {
            LocalDate startDate = date;
            LocalDate endDate = date.plusDays(1);

            String url = UriComponentsBuilder
                .fromHttpUrl(apiBaseUrl + "/v2/reference/news")
                .queryParam("ticker", ticker)
                .queryParam("published_utc.gte", startDate.format(DateTimeFormatter.ISO_DATE))
                .queryParam("published_utc.lt", endDate.format(DateTimeFormatter.ISO_DATE))
                .queryParam("limit", 100)
                .queryParam("sort", "published_utc")
                .queryParam("apiKey", apiKey)
                .toUriString();

            String response = restClient.get()
                .uri(url)
                .retrieve()
                .body(String.class);

            if (response == null) {
                return articles;
            }

            JsonNode root = new tools.jackson.databind.ObjectMapper().readTree(response);
            JsonNode results = root.get("results");

            if (results != null && results.isArray()) {
                for (JsonNode result : results) {
                    NewsArticle article = parseNewsArticle(result);
                    if (article != null) {
                        articles.add(article);
                    }
                }
            }

        } catch (Exception e) {
            log.error("Error fetching news from Polygon.io for {}", ticker, e);
        }

        return articles;
    }

    private NewsArticle parseNewsArticle(JsonNode node) {
        try {
            NewsArticle article = new NewsArticle();
            article.title = node.get("title") != null ? node.get("title").asText() : "";

            // Extract sentiment from insights
            JsonNode insights = node.get("insights");
            if (insights != null && insights.isArray() && insights.size() > 0) {
                JsonNode firstInsight = insights.get(0);
                String sentiment = firstInsight.get("sentiment") != null ?
                    firstInsight.get("sentiment").asText() : "neutral";
                article.sentiment = sentiment;
            }

            return article;
        } catch (Exception e) {
            log.error("Error parsing news article", e);
            return null;
        }
    }

    private SentimentAggregation aggregateSentiment(List<NewsArticle> articles) {
        SentimentAggregation agg = new SentimentAggregation();

        int positive = 0, negative = 0;

        for (NewsArticle article : articles) {
            if ("positive".equalsIgnoreCase(article.sentiment)) {
                positive++;
            } else if ("negative".equalsIgnoreCase(article.sentiment)) {
                negative++;
            }
        }

        // Calculate composite sentiment score (-1.0 to 1.0)
        int total = articles.size();
        double score = (double)(positive - negative) / total;
        agg.score = score;

        return agg;
    }

    private String buildDailyNewsSummary(List<NewsArticle> articles) {
        StringBuilder sb = new StringBuilder();
        int count = 0;
        for (NewsArticle article : articles) {
            if (article.title == null || article.title.isBlank()) {
                continue;
            }
            if (count > 0) {
                sb.append(" | ");
            }
            sb.append(article.title.trim());
            count++;
            if (count >= 3 || sb.length() >= 700) {
                break;
            }
        }
        return sb.isEmpty() ? null : sb.toString();
    }

    static class NewsArticle {
        String title;
        String sentiment = "neutral";
    }

    static class SentimentAggregation {
        double score;
    }
}

package com.tradepulseai.stockservice.service;

import com.tradepulseai.stockservice.dto.stock.StockInsightsResponseDTO;
import com.tradepulseai.stockservice.exception.StockNotFoundException;
import com.tradepulseai.stockservice.model.AllStocksLastValueCache;
import com.tradepulseai.stockservice.model.Stock;
import com.tradepulseai.stockservice.model.StockMarketData;
import com.tradepulseai.stockservice.model.StockMetrics;
import com.tradepulseai.stockservice.repository.StockMarketDataRepository;
import com.tradepulseai.stockservice.repository.StockMetricsRepository;
import com.tradepulseai.stockservice.repository.StockRepository;
import org.springframework.data.domain.PageRequest;
import org.springframework.stereotype.Service;

import java.math.BigDecimal;
import java.math.MathContext;
import java.math.RoundingMode;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;
import java.util.Map;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.core.type.TypeReference;
@Service
public class StockInsightsService {

    private static final int HISTORY_LOOKBACK_ROWS = 800;
    private static final MathContext MATH_CONTEXT = new MathContext(12, RoundingMode.HALF_UP);
    private static final BigDecimal HUNDRED = BigDecimal.valueOf(100);

    private final StockRepository stockRepository;
    private final StockMarketDataRepository stockMarketDataRepository;
    private final StockMetricsRepository stockMetricsRepository;
    private final AllStocksLastValueCacheService allStocksLastValueCacheService;

    public StockInsightsService(
            StockRepository stockRepository,
            StockMarketDataRepository stockMarketDataRepository,
            StockMetricsRepository stockMetricsRepository,
            AllStocksLastValueCacheService allStocksLastValueCacheService
    ) {
        this.stockRepository = stockRepository;
        this.stockMarketDataRepository = stockMarketDataRepository;
        this.stockMetricsRepository = stockMetricsRepository;
        this.allStocksLastValueCacheService = allStocksLastValueCacheService;
    }

    public StockInsightsResponseDTO getInsights(Long stockId) {
        Stock stock = stockRepository.findById(stockId)
                .orElseThrow(() -> new StockNotFoundException("Stock not found with id: " + stockId));

        List<StockMarketData> historyAsc = stockMarketDataRepository
                .findRecentByStockId(stockId, PageRequest.of(0, HISTORY_LOOKBACK_ROWS));
        if (historyAsc.isEmpty()) {
            throw new StockNotFoundException("Stock insights not available yet for id: " + stockId);
        }
        historyAsc = new ArrayList<>(historyAsc);
        historyAsc.sort(Comparator.comparing(StockMarketData::getTradingDate));

        StockMarketData latestHistorical = historyAsc.getLast();
        StockMarketData priorHistorical = historyAsc.size() > 1 ? historyAsc.get(historyAsc.size() - 2) : null;
        AllStocksLastValueCache realtime = allStocksLastValueCacheService.getCacheEntryByStockId(stockId);
        StockMetrics metrics = stockMetricsRepository.findById(stockId).orElse(null);

        // Current Performance — driven by realtime cache; falls back to latest daily OHLC when market is closed
        BigDecimal currentPrice = resolveCurrentPrice(realtime, latestHistorical);
        BigDecimal previousClose = resolvePreviousClose(realtime, latestHistorical, priorHistorical);
        BigDecimal dailyChange = currentPrice != null && previousClose != null ? currentPrice.subtract(previousClose) : null;
        BigDecimal dailyChangePercent = resolveDailyChangePercent(realtime, previousClose, currentPrice);

        BigDecimal high52Week = metrics == null ? null : metrics.getHigh52w();
        BigDecimal low52Week = metrics == null ? null : metrics.getLow52w();
        BigDecimal distanceFromHighPercent = metrics == null ? null : metrics.getDistanceFromHighPercent();
        BigDecimal distanceFromLowPercent = metrics == null ? null : metrics.getDistanceFromLowPercent();

        BigDecimal oneWeekReturn = metrics == null ? null : metrics.getWeekReturn();
        BigDecimal oneMonthReturn = metrics == null ? null : metrics.getMonthReturn();
        BigDecimal threeMonthReturn = metrics == null ? null : metrics.getThreeMonthReturn();
        BigDecimal sixMonthReturn = metrics == null ? null : metrics.getSixMonthReturn();
        BigDecimal oneYearReturn = metrics == null ? null : metrics.getYearReturn();
        BigDecimal threeYearReturn = metrics == null ? null : metrics.getThreeYearReturn();

        long latestTradingDayVolume = metrics != null && metrics.getLatestTradingDayVolume() != null
                ? metrics.getLatestTradingDayVolume()
                : resolveLatestTradingDayVolume(latestHistorical);
        String latestTradingDate = metrics != null && metrics.getLatestTradingDate() != null
                ? metrics.getLatestTradingDate().toString()
                : latestHistorical.getTradingDate() == null ? null : latestHistorical.getTradingDate().toString();
        BigDecimal average30DayVolume = metrics == null ? null : metrics.getAvgVolume30d();
        BigDecimal relativeVolume = metrics == null ? null : metrics.getRelativeVolume();

        BigDecimal volatility30Day = metrics == null ? null : metrics.getVolatility30d();
        BigDecimal volatility90Day = metrics == null ? null : metrics.getVolatility90d();

        BigDecimal sma20 = latestHistorical.getSma20();
        BigDecimal sma50 = latestHistorical.getSma50();
        BigDecimal sma200 = latestHistorical.getSma200();
        Boolean goldenCross = metrics == null ? null : metrics.getGoldenCross();
        Boolean deathCross = metrics == null ? null : metrics.getDeathCross();

        BigDecimal rsi14 = metrics == null ? null : metrics.getRsi14();
        MacdResult macdResult = new MacdResult(
                metrics == null ? null : metrics.getMacd(),
                metrics == null ? null : metrics.getMacdSignal());
        BigDecimal momentum30Day = metrics == null ? null : metrics.getMomentum30d();
        RiskSummary riskSummary = new RiskSummary(
                metrics == null ? null : metrics.getSharpeRatio(),
                metrics == null ? null : metrics.getSortinoRatio());
        DrawdownSummary drawdownSummary = resolveDrawdownSummary(metrics);
        DistributionSummary distributionSummary = resolveDistributionSummary(metrics);
        List<StockInsightsResponseDTO.MonthlyReturnHeatmapCellDTO> monthlyReturnsHeatmap = resolveMonthlyReturnsHeatmap(metrics);
        List<StockInsightsResponseDTO.StockHistoryPointDTO> historyPoints = buildHistoryPoints(historyAsc);

        return new StockInsightsResponseDTO(
                String.valueOf(stock.getStockId()),
                stock.getSymbol(),
                stock.getName(),
                resolveExchange(stock),
                stock.getMarket(),
                resolveLastUpdated(realtime, latestHistorical),
                new StockInsightsResponseDTO.CurrentPerformanceDTO(
                        toDouble(currentPrice),
                        toDouble(previousClose),
                        toDouble(dailyChange),
                        toDouble(dailyChangePercent)
                ),
                new StockInsightsResponseDTO.Metrics52WeekDTO(
                        toDouble(high52Week),
                        toDouble(low52Week),
                        toDouble(distanceFromHighPercent),
                        toDouble(distanceFromLowPercent)
                ),
                new StockInsightsResponseDTO.ReturnMetricsDTO(
                        toDouble(oneWeekReturn),
                        toDouble(oneMonthReturn),
                        toDouble(threeMonthReturn),
                        toDouble(sixMonthReturn),
                        toDouble(oneYearReturn),
                        toDouble(threeYearReturn)
                ),
                new StockInsightsResponseDTO.VolumeMetricsDTO(
                        latestTradingDayVolume,
                        latestTradingDate,
                        toDouble(average30DayVolume),
                        toDouble(relativeVolume)
                ),
                new StockInsightsResponseDTO.VolatilityMetricsDTO(
                        toDouble(volatility30Day),
                        toDouble(volatility90Day)
                ),
                new StockInsightsResponseDTO.TrendMetricsDTO(
                        toDouble(sma20),
                        toDouble(sma50),
                        toDouble(sma200),
                        goldenCross,
                        deathCross
                ),
                new StockInsightsResponseDTO.MomentumMetricsDTO(
                        toDouble(rsi14),
                        toDouble(macdResult.macd()),
                        toDouble(macdResult.signal()),
                        toDouble(momentum30Day)
                ),
                new StockInsightsResponseDTO.RiskMetricsDTO(
                        toDouble(riskSummary.sharpeRatio()),
                        toDouble(riskSummary.sortinoRatio()),
                        toDouble(drawdownSummary.maxDrawdown())
                ),
                new StockInsightsResponseDTO.PerformanceDistributionDTO(
                        distributionSummary.positiveDays(),
                        distributionSummary.negativeDays(),
                        distributionSummary.flatDays()
                ),
                new StockInsightsResponseDTO.DrawdownAnalysisDTO(
                        toDouble(drawdownSummary.maxDrawdown()),
                        drawdownSummary.peakDate() == null ? null : drawdownSummary.peakDate().toString(),
                        drawdownSummary.troughDate() == null ? null : drawdownSummary.troughDate().toString()
                ),
                monthlyReturnsHeatmap,
                historyPoints
        );
    }

    private String resolveExchange(Stock stock) {
        if (stock.getExchange() == null) {
            return null;
        }
        if (stock.getExchange().getAcronym() != null && !stock.getExchange().getAcronym().isBlank()) {
            return stock.getExchange().getAcronym();
        }
        return stock.getExchange().getMic();
    }

    private String resolveLastUpdated(AllStocksLastValueCache realtime, StockMarketData latestHistorical) {
        if (realtime != null && realtime.getAggregateUpdatedAt() != null) {
            return realtime.getAggregateUpdatedAt().toString();
        }
        return latestHistorical.getUpdatedAt() == null ? null : latestHistorical.getUpdatedAt().toString();
    }

    // Current price: realtime cache when market is open, latest daily close otherwise
    private BigDecimal resolveCurrentPrice(AllStocksLastValueCache realtime, StockMarketData latestHistorical) {
        if (realtime != null && realtime.getCachedClose() != null) {
            return realtime.getCachedClose();
        }
        return latestHistorical.getClosePrice();
    }

    // Previous close: latest daily OHLC close when realtime is available (intraday vs yesterday),
    // or second-to-last daily OHLC close when market is closed (both current and latest are the same row).
    private BigDecimal resolvePreviousClose(AllStocksLastValueCache realtime, StockMarketData latestHistorical, StockMarketData priorHistorical) {
        boolean hasRealtime = realtime != null && realtime.getCachedClose() != null;
        if (hasRealtime) {
            // Realtime price is intraday — previous close is yesterday's daily close
            return latestHistorical.getClosePrice();
        }
        // No realtime — current price IS the latest daily close, so previous close is the one before it
        return priorHistorical == null ? null : priorHistorical.getClosePrice();
    }

    // Daily change %: prefer the pre-computed change percent from realtime cache (accurate intraday),
    // fall back to computing from current vs previous close.
    private BigDecimal resolveDailyChangePercent(AllStocksLastValueCache realtime, BigDecimal previousClose, BigDecimal currentPrice) {
        if (realtime != null && realtime.getCachedChangePercent() != null) {
            return realtime.getCachedChangePercent();
        }
        return percentChange(previousClose, currentPrice);
    }

    private long resolveLatestTradingDayVolume(StockMarketData latestHistorical) {
        return latestHistorical.getVolume() == null ? 0L : latestHistorical.getVolume();
    }

    private List<StockInsightsResponseDTO.StockHistoryPointDTO> buildHistoryPoints(List<StockMarketData> historyAsc) {
        List<StockInsightsResponseDTO.StockHistoryPointDTO> points = new ArrayList<>(historyAsc.size());
        for (StockMarketData point : historyAsc) {

            points.add(new StockInsightsResponseDTO.StockHistoryPointDTO(
                    point.getTradingDate() == null ? null : point.getTradingDate().toString(),
                    toDouble(point.getOpenPrice()),
                    toDouble(point.getHighPrice()),
                    toDouble(point.getLowPrice()),
                    toDouble(point.getClosePrice()),
                    point.getVolume(),
                    toDouble(point.getSma20()),
                    toDouble(point.getSma50()),
                    toDouble(point.getSma200()),
                    toDouble(point.getVolatility30d()),
                    toDouble(point.getVolatility90d()),
                    toDouble(point.getDailyReturnPercent())
            ));
        }
         return points;
    }

    private List<StockInsightsResponseDTO.MonthlyReturnHeatmapCellDTO> resolveMonthlyReturnsHeatmap(StockMetrics metrics) {
        if (metrics != null && metrics.getMonthlyReturnsHeatmap() != null) {
            try {
                ObjectMapper mapper = new ObjectMapper();
                List<Map<String, Object>> cells = mapper.readValue(
                    metrics.getMonthlyReturnsHeatmap(),
                    new TypeReference<>() {}
                );
                List<StockInsightsResponseDTO.MonthlyReturnHeatmapCellDTO> result = new ArrayList<>();
                for (Map<String, Object> cell : cells) {
                    int year = ((Number) cell.get("year")).intValue();
                    int month = ((Number) cell.get("month")).intValue();
                    Double returnPercent = cell.get("returnPercent") != null
                        ? ((Number) cell.get("returnPercent")).doubleValue()
                        : null;
                    result.add(new StockInsightsResponseDTO.MonthlyReturnHeatmapCellDTO(year, month, returnPercent));
                }
                return result;
            } catch (Exception e) {
                return List.of();
            }
        }
        return List.of();
    }

    private DistributionSummary resolveDistributionSummary(StockMetrics metrics) {
        if (metrics != null
                && metrics.getPositiveDays1y() != null
                && metrics.getNegativeDays1y() != null
                && metrics.getFlatDays1y() != null) {
            return new DistributionSummary(
                    metrics.getPositiveDays1y(),
                    metrics.getNegativeDays1y(),
                    metrics.getFlatDays1y());
        }
        return new DistributionSummary(0, 0, 0);
    }

    private DrawdownSummary resolveDrawdownSummary(StockMetrics metrics) {
        if (metrics != null
                && metrics.getMaxDrawdown() != null
                && metrics.getDrawdownPeakDate() != null
                && metrics.getDrawdownTroughDate() != null) {
            return new DrawdownSummary(
                    metrics.getMaxDrawdown(),
                    metrics.getDrawdownPeakDate(),
                    metrics.getDrawdownTroughDate());
        }
        return new DrawdownSummary(null, null, null);
    }

    private BigDecimal percentChange(BigDecimal baseline, BigDecimal current) {
        if (baseline == null || current == null || baseline.compareTo(BigDecimal.ZERO) == 0) {
            return null;
        }
        return current.subtract(baseline).divide(baseline, MATH_CONTEXT).multiply(HUNDRED, MATH_CONTEXT);
    }

    private Double toDouble(BigDecimal value) {
        return value == null ? null : value.setScale(2, RoundingMode.HALF_UP).doubleValue();
    }

    private record MacdResult(BigDecimal macd, BigDecimal signal) {
    }

    private record RiskSummary(BigDecimal sharpeRatio, BigDecimal sortinoRatio) {
    }

    private record DistributionSummary(int positiveDays, int negativeDays, int flatDays) {
    }


    private record DrawdownSummary(BigDecimal maxDrawdown, LocalDate peakDate, LocalDate troughDate) {
    }

}

package com.tradepulseai.stockservice.service;

import com.tradepulseai.stockservice.dto.stock.AnalyticsNewsItemDTO;
import com.tradepulseai.stockservice.dto.stock.StockInsightsResponseDTO;
import com.tradepulseai.stockservice.exception.StockNotFoundException;
import com.tradepulseai.stockservice.model.AllStocksLastValueCache;
import com.tradepulseai.stockservice.model.Stock;
import com.tradepulseai.stockservice.model.StockMarketData;
import com.tradepulseai.stockservice.model.StockMetrics;
import com.tradepulseai.stockservice.repository.StockMarketDataRepository;
import com.tradepulseai.stockservice.repository.StockMetricsRepository;
import com.tradepulseai.stockservice.repository.StockRepository;
import org.springframework.data.domain.PageRequest;
import org.springframework.stereotype.Service;

import java.math.BigDecimal;
import java.math.MathContext;
import java.math.RoundingMode;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.List;
import java.util.Map;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.core.type.TypeReference;
@Service
public class StockInsightsService {

    private static final int HISTORY_LOOKBACK_ROWS = 800;
    private static final MathContext MATH_CONTEXT = new MathContext(12, RoundingMode.HALF_UP);
    private static final BigDecimal HUNDRED = BigDecimal.valueOf(100);

    private final StockRepository stockRepository;
    private final StockMarketDataRepository stockMarketDataRepository;
    private final StockMetricsRepository stockMetricsRepository;
    private final AllStocksLastValueCacheService allStocksLastValueCacheService;

    public StockInsightsService(
            StockRepository stockRepository,
            StockMarketDataRepository stockMarketDataRepository,
            StockMetricsRepository stockMetricsRepository,
            AllStocksLastValueCacheService allStocksLastValueCacheService
    ) {
        this.stockRepository = stockRepository;
        this.stockMarketDataRepository = stockMarketDataRepository;
        this.stockMetricsRepository = stockMetricsRepository;
        this.allStocksLastValueCacheService = allStocksLastValueCacheService;
    }

    public StockInsightsResponseDTO getInsights(Long stockId) {
        Stock stock = stockRepository.findById(stockId)
                .orElseThrow(() -> new StockNotFoundException("Stock not found with id: " + stockId));

        List<StockMarketData> historyAsc = stockMarketDataRepository
                .findRecentByStockId(stockId, PageRequest.of(0, HISTORY_LOOKBACK_ROWS));
        if (historyAsc.isEmpty()) {
            throw new StockNotFoundException("Stock insights not available yet for id: " + stockId);
        }
        historyAsc = new ArrayList<>(historyAsc);
        historyAsc.sort(Comparator.comparing(StockMarketData::getTradingDate));

        StockMarketData latestHistorical = historyAsc.getLast();
        StockMarketData priorHistorical = historyAsc.size() > 1 ? historyAsc.get(historyAsc.size() - 2) : null;
        AllStocksLastValueCache realtime = allStocksLastValueCacheService.getCacheEntryByStockId(stockId);
        StockMetrics metrics = stockMetricsRepository.findById(stockId).orElse(null);

        // Current Performance — driven by realtime cache; falls back to latest daily OHLC when market is closed
        BigDecimal currentPrice = resolveCurrentPrice(realtime, latestHistorical);
        BigDecimal previousClose = resolvePreviousClose(realtime, latestHistorical, priorHistorical);
        BigDecimal dailyChange = currentPrice != null && previousClose != null ? currentPrice.subtract(previousClose) : null;
        BigDecimal dailyChangePercent = resolveDailyChangePercent(realtime, previousClose, currentPrice);

        BigDecimal high52Week = metrics == null ? null : metrics.getHigh52w();
        BigDecimal low52Week = metrics == null ? null : metrics.getLow52w();
        BigDecimal distanceFromHighPercent = metrics == null ? null : metrics.getDistanceFromHighPercent();
        BigDecimal distanceFromLowPercent = metrics == null ? null : metrics.getDistanceFromLowPercent();

        BigDecimal oneWeekReturn = metrics == null ? null : metrics.getWeekReturn();
        BigDecimal oneMonthReturn = metrics == null ? null : metrics.getMonthReturn();
        BigDecimal threeMonthReturn = metrics == null ? null : metrics.getThreeMonthReturn();
        BigDecimal sixMonthReturn = metrics == null ? null : metrics.getSixMonthReturn();
        BigDecimal oneYearReturn = metrics == null ? null : metrics.getYearReturn();
        BigDecimal threeYearReturn = metrics == null ? null : metrics.getThreeYearReturn();

        long latestTradingDayVolume = metrics != null && metrics.getLatestTradingDayVolume() != null
                ? metrics.getLatestTradingDayVolume()
                : resolveLatestTradingDayVolume(latestHistorical);
        String latestTradingDate = metrics != null && metrics.getLatestTradingDate() != null
                ? metrics.getLatestTradingDate().toString()
                : latestHistorical.getTradingDate() == null ? null : latestHistorical.getTradingDate().toString();
        BigDecimal average30DayVolume = metrics == null ? null : metrics.getAvgVolume30d();
        BigDecimal relativeVolume = metrics == null ? null : metrics.getRelativeVolume();

        BigDecimal volatility30Day = metrics == null ? null : metrics.getVolatility30d();
        BigDecimal volatility90Day = metrics == null ? null : metrics.getVolatility90d();

        BigDecimal sma20 = latestHistorical.getSma20();
        BigDecimal sma50 = latestHistorical.getSma50();
        BigDecimal sma200 = latestHistorical.getSma200();
        Boolean goldenCross = metrics == null ? null : metrics.getGoldenCross();
        Boolean deathCross = metrics == null ? null : metrics.getDeathCross();

        BigDecimal rsi14 = metrics == null ? null : metrics.getRsi14();
        MacdResult macdResult = new MacdResult(
                metrics == null ? null : metrics.getMacd(),
                metrics == null ? null : metrics.getMacdSignal());
        BigDecimal momentum30Day = metrics == null ? null : metrics.getMomentum30d();
        RiskSummary riskSummary = new RiskSummary(
                metrics == null ? null : metrics.getSharpeRatio(),
                metrics == null ? null : metrics.getSortinoRatio());
        DrawdownSummary drawdownSummary = resolveDrawdownSummary(metrics);
        DistributionSummary distributionSummary = resolveDistributionSummary(metrics);
        List<StockInsightsResponseDTO.DailyNewsDTO> latestNews = buildLatestNews(historyAsc);
        List<StockInsightsResponseDTO.MonthlyReturnHeatmapCellDTO> monthlyReturnsHeatmap = resolveMonthlyReturnsHeatmap(metrics);
        List<StockInsightsResponseDTO.StockHistoryPointDTO> historyPoints = buildHistoryPoints(historyAsc);

        return new StockInsightsResponseDTO(
                String.valueOf(stock.getStockId()),
                stock.getSymbol(),
                stock.getName(),
                resolveExchange(stock),
                stock.getMarket(),
                resolveLastUpdated(realtime, latestHistorical),
                new StockInsightsResponseDTO.CurrentPerformanceDTO(
                        toDouble(currentPrice),
                        toDouble(previousClose),
                        toDouble(dailyChange),
                        toDouble(dailyChangePercent)
                ),
                new StockInsightsResponseDTO.Metrics52WeekDTO(
                        toDouble(high52Week),
                        toDouble(low52Week),
                        toDouble(distanceFromHighPercent),
                        toDouble(distanceFromLowPercent)
                ),
                new StockInsightsResponseDTO.ReturnMetricsDTO(
                        toDouble(oneWeekReturn),
                        toDouble(oneMonthReturn),
                        toDouble(threeMonthReturn),
                        toDouble(sixMonthReturn),
                        toDouble(oneYearReturn),
                        toDouble(threeYearReturn)
                ),
                new StockInsightsResponseDTO.VolumeMetricsDTO(
                        latestTradingDayVolume,
                        latestTradingDate,
                        toDouble(average30DayVolume),
                        toDouble(relativeVolume)
                ),
                new StockInsightsResponseDTO.VolatilityMetricsDTO(
                        toDouble(volatility30Day),
                        toDouble(volatility90Day)
                ),
                new StockInsightsResponseDTO.TrendMetricsDTO(
                        toDouble(sma20),
                        toDouble(sma50),
                        toDouble(sma200),
                        goldenCross,
                        deathCross
                ),
                new StockInsightsResponseDTO.MomentumMetricsDTO(
                        toDouble(rsi14),
                        toDouble(macdResult.macd()),
                        toDouble(macdResult.signal()),
                        toDouble(momentum30Day)
                ),
                new StockInsightsResponseDTO.RiskMetricsDTO(
                        toDouble(riskSummary.sharpeRatio()),
                        toDouble(riskSummary.sortinoRatio()),
                        toDouble(drawdownSummary.maxDrawdown())
                ),
                new StockInsightsResponseDTO.PerformanceDistributionDTO(
                        distributionSummary.positiveDays(),
                        distributionSummary.negativeDays(),
                        distributionSummary.flatDays()
                ),
                new StockInsightsResponseDTO.DrawdownAnalysisDTO(
                        toDouble(drawdownSummary.maxDrawdown()),
                        drawdownSummary.peakDate() == null ? null : drawdownSummary.peakDate().toString(),
                        drawdownSummary.troughDate() == null ? null : drawdownSummary.troughDate().toString()
                ),
                latestNews,
                monthlyReturnsHeatmap,
                historyPoints
        );
    }

    public List<AnalyticsNewsItemDTO> getLatestMarketNews(int limit) {
        int pageSize = Math.max(1, Math.min(limit, 50));
        List<StockMarketData> rows = stockMarketDataRepository.findByDailyNewsIsNotNullOrderByTradingDateDesc(
                PageRequest.of(0, pageSize)
        );
        List<AnalyticsNewsItemDTO> response = new ArrayList<>();
        for (StockMarketData row : rows) {
            if (row.getDailyNews() == null || row.getDailyNews().isBlank() || row.getStock() == null) {
                continue;
            }
            response.add(new AnalyticsNewsItemDTO(
                    row.getStock().getStockId(),
                    row.getStock().getSymbol(),
                    row.getTradingDate() == null ? null : row.getTradingDate().toString(),
                    row.getDailyNews(),
                    toDouble(row.getSentimentScore()),
                    row.getNewsCount()
            ));
        }
        return response;
    }

    private String resolveExchange(Stock stock) {
        if (stock.getExchange() == null) {
            return null;
        }
        if (stock.getExchange().getAcronym() != null && !stock.getExchange().getAcronym().isBlank()) {
            return stock.getExchange().getAcronym();
        }
        return stock.getExchange().getMic();
    }

    private String resolveLastUpdated(AllStocksLastValueCache realtime, StockMarketData latestHistorical) {
        if (realtime != null && realtime.getAggregateUpdatedAt() != null) {
            return realtime.getAggregateUpdatedAt().toString();
        }
        return latestHistorical.getUpdatedAt() == null ? null : latestHistorical.getUpdatedAt().toString();
    }

    // Current price: realtime cache when market is open, latest daily close otherwise
    private BigDecimal resolveCurrentPrice(AllStocksLastValueCache realtime, StockMarketData latestHistorical) {
        if (realtime != null && realtime.getCachedClose() != null) {
            return realtime.getCachedClose();
        }
        return latestHistorical.getClosePrice();
    }

    // Previous close: latest daily OHLC close when realtime is available (intraday vs yesterday),
    // or second-to-last daily OHLC close when market is closed (both current and latest are the same row).
    private BigDecimal resolvePreviousClose(AllStocksLastValueCache realtime, StockMarketData latestHistorical, StockMarketData priorHistorical) {
        boolean hasRealtime = realtime != null && realtime.getCachedClose() != null;
        if (hasRealtime) {
            // Realtime price is intraday — previous close is yesterday's daily close
            return latestHistorical.getClosePrice();
        }
        // No realtime — current price IS the latest daily close, so previous close is the one before it
        return priorHistorical == null ? null : priorHistorical.getClosePrice();
    }

    // Daily change %: prefer the pre-computed change percent from realtime cache (accurate intraday),
    // fall back to computing from current vs previous close.
    private BigDecimal resolveDailyChangePercent(AllStocksLastValueCache realtime, BigDecimal previousClose, BigDecimal currentPrice) {
        if (realtime != null && realtime.getCachedChangePercent() != null) {
            return realtime.getCachedChangePercent();
        }
        return percentChange(previousClose, currentPrice);
    }

    private long resolveLatestTradingDayVolume(StockMarketData latestHistorical) {
        return latestHistorical.getVolume() == null ? 0L : latestHistorical.getVolume();
    }

    private List<StockInsightsResponseDTO.StockHistoryPointDTO> buildHistoryPoints(List<StockMarketData> historyAsc) {
        List<StockInsightsResponseDTO.StockHistoryPointDTO> points = new ArrayList<>(historyAsc.size());
        for (StockMarketData point : historyAsc) {

            points.add(new StockInsightsResponseDTO.StockHistoryPointDTO(
                    point.getTradingDate() == null ? null : point.getTradingDate().toString(),
                    toDouble(point.getOpenPrice()),
                    toDouble(point.getHighPrice()),
                    toDouble(point.getLowPrice()),
                    toDouble(point.getClosePrice()),
                    point.getVolume(),
                    toDouble(point.getSma20()),
                    toDouble(point.getSma50()),
                    toDouble(point.getSma200()),
                    toDouble(point.getVolatility30d()),
                    toDouble(point.getVolatility90d()),
                    toDouble(point.getDailyReturnPercent())
            ));
        }
         return points;
    }

    private List<StockInsightsResponseDTO.DailyNewsDTO> buildLatestNews(List<StockMarketData> historyAsc) {
        List<StockInsightsResponseDTO.DailyNewsDTO> rows = new ArrayList<>();
        for (int i = historyAsc.size() - 1; i >= 0; i--) {
            StockMarketData point = historyAsc.get(i);
            if (point.getDailyNews() == null || point.getDailyNews().isBlank()) {
                continue;
            }
            rows.add(new StockInsightsResponseDTO.DailyNewsDTO(
                    point.getTradingDate() == null ? null : point.getTradingDate().toString(),
                    point.getDailyNews(),
                    toDouble(point.getSentimentScore()),
                    point.getNewsCount()
            ));
            if (rows.size() >= 5) {
                break;
            }
        }
        return rows;
    }

    private List<StockInsightsResponseDTO.MonthlyReturnHeatmapCellDTO> resolveMonthlyReturnsHeatmap(StockMetrics metrics) {
        if (metrics != null && metrics.getMonthlyReturnsHeatmap() != null) {
            try {
                ObjectMapper mapper = new ObjectMapper();
                List<Map<String, Object>> cells = mapper.readValue(
                    metrics.getMonthlyReturnsHeatmap(),
                    new TypeReference<>() {}
                );
                List<StockInsightsResponseDTO.MonthlyReturnHeatmapCellDTO> result = new ArrayList<>();
                for (Map<String, Object> cell : cells) {
                    int year = ((Number) cell.get("year")).intValue();
                    int month = ((Number) cell.get("month")).intValue();
                    Double returnPercent = cell.get("returnPercent") != null
                        ? ((Number) cell.get("returnPercent")).doubleValue()
                        : null;
                    result.add(new StockInsightsResponseDTO.MonthlyReturnHeatmapCellDTO(year, month, returnPercent));
                }
                return result;
            } catch (Exception e) {
                return List.of();
            }
        }
        return List.of();
    }

    private DistributionSummary resolveDistributionSummary(StockMetrics metrics) {
        if (metrics != null
                && metrics.getPositiveDays1y() != null
                && metrics.getNegativeDays1y() != null
                && metrics.getFlatDays1y() != null) {
            return new DistributionSummary(
                    metrics.getPositiveDays1y(),
                    metrics.getNegativeDays1y(),
                    metrics.getFlatDays1y());
        }
        return new DistributionSummary(0, 0, 0);
    }

    private DrawdownSummary resolveDrawdownSummary(StockMetrics metrics) {
        if (metrics != null
                && metrics.getMaxDrawdown() != null
                && metrics.getDrawdownPeakDate() != null
                && metrics.getDrawdownTroughDate() != null) {
            return new DrawdownSummary(
                    metrics.getMaxDrawdown(),
                    metrics.getDrawdownPeakDate(),
                    metrics.getDrawdownTroughDate());
        }
        return new DrawdownSummary(null, null, null);
    }

    private BigDecimal percentChange(BigDecimal baseline, BigDecimal current) {
        if (baseline == null || current == null || baseline.compareTo(BigDecimal.ZERO) == 0) {
            return null;
        }
        return current.subtract(baseline).divide(baseline, MATH_CONTEXT).multiply(HUNDRED, MATH_CONTEXT);
    }

    private Double toDouble(BigDecimal value) {
        return value == null ? null : value.setScale(2, RoundingMode.HALF_UP).doubleValue();
    }

    private record MacdResult(BigDecimal macd, BigDecimal signal) {
    }

    private record RiskSummary(BigDecimal sharpeRatio, BigDecimal sortinoRatio) {
    }

    private record DistributionSummary(int positiveDays, int negativeDays, int flatDays) {
    }


    private record DrawdownSummary(BigDecimal maxDrawdown, LocalDate peakDate, LocalDate troughDate) {
    }

}

package com.tradepulseai.stockservice.service;

import com.tradepulseai.stockservice.model.Stock;
import com.tradepulseai.stockservice.model.StockMarketData;
import com.tradepulseai.stockservice.model.StockMetrics;
import com.tradepulseai.stockservice.repository.StockMarketDataRepository;
import com.tradepulseai.stockservice.repository.StockMetricsRepository;
import com.tradepulseai.stockservice.repository.StockRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.data.domain.PageRequest;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.math.MathContext;
import java.math.RoundingMode;
import java.time.LocalDate;
import java.time.YearMonth;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import com.fasterxml.jackson.databind.ObjectMapper;

@Service
public class StockMetricsRefreshService {

    private static final Logger log = LoggerFactory.getLogger(StockMetricsRefreshService.class);
    private static final int LOOKBACK_ROWS = 800;
    private static final int ONE_WEEK_PERIODS = 5;
    private static final int ONE_MONTH_PERIODS = 21;
    private static final int THREE_MONTH_PERIODS = 63;
    private static final int SIX_MONTH_PERIODS = 126;
    private static final int ONE_YEAR_PERIODS = 252;
    private static final int THREE_YEAR_PERIODS = 756;
    private static final double SQRT_252 = Math.sqrt(252.0d);
    private static final BigDecimal ZERO = BigDecimal.ZERO;
    private static final MathContext MATH_CONTEXT = new MathContext(12, RoundingMode.HALF_UP);
    private static final BigDecimal HUNDRED = BigDecimal.valueOf(100);

    private final StockRepository stockRepository;
    private final StockMarketDataRepository stockMarketDataRepository;
    private final StockMetricsRepository stockMetricsRepository;

    public StockMetricsRefreshService(
            StockRepository stockRepository,
            StockMarketDataRepository stockMarketDataRepository,
            StockMetricsRepository stockMetricsRepository) {
        this.stockRepository = stockRepository;
        this.stockMarketDataRepository = stockMarketDataRepository;
        this.stockMetricsRepository = stockMetricsRepository;
    }

    @Transactional
    public void refreshAllForLatestOhlc(String trigger) {
        Optional<LocalDate> maxTradingDate = stockMarketDataRepository.findMaxTradingDate();
        if (maxTradingDate.isEmpty()) {
            log.info("Skipping stock metrics refresh ({}) because no OHLC rows exist.", trigger);
            return;
        }

        List<Stock> stocks = stockRepository.findAllByOrderByStockIdAsc();
        if (stocks.isEmpty()) {
            log.info("Skipping stock metrics refresh ({}) because stocks table is empty.", trigger);
            return;
        }

        List<StockMetrics> metricsRows = new ArrayList<>();
        List<StockMarketData> indicatorRows = new ArrayList<>();
        for (Stock stock : stocks) {
            Long stockId = stock.getStockId();
            if (stockId == null) {
                continue;
            }

            List<StockMarketData> historyDesc = stockMarketDataRepository.findRecentByStockId(stockId, PageRequest.of(0, LOOKBACK_ROWS));
            if (historyDesc.isEmpty()) {
                continue;
            }

            historyDesc.sort(Comparator.comparing(StockMarketData::getTradingDate));
            applyIndicatorsToHistory(historyDesc);
            indicatorRows.addAll(historyDesc);
            StockMetrics metrics = buildMetrics(stockId, historyDesc);
            metricsRows.add(metrics);
        }

        if (metricsRows.isEmpty()) {
            log.info("Stock metrics refresh ({}) found no computable rows.", trigger);
            return;
        }

        stockMarketDataRepository.saveAll(indicatorRows);
        stockMetricsRepository.saveAll(metricsRows);
        log.info("Stock metrics refresh ({}) upserted {} rows for latest OHLC date {}.",
                trigger, metricsRows.size(), maxTradingDate.get());
    }

    private void applyIndicatorsToHistory(List<StockMarketData> historyAsc) {
        List<BigDecimal> closes = historyAsc.stream().map(StockMarketData::getClosePrice).toList();
        for (int index = 0; index < historyAsc.size(); index++) {
            StockMarketData row = historyAsc.get(index);
            row.setSma20(scaleNullable(simpleMovingAverageAt(closes, index, 20)));
            row.setSma50(scaleNullable(simpleMovingAverageAt(closes, index, 50)));
            row.setSma200(scaleNullable(simpleMovingAverageAt(closes, index, 200)));
            row.setVolatility30d(scaleNullable(computeAnnualizedVolatilityAt(closes, index, 30)));
            row.setVolatility90d(scaleNullable(computeAnnualizedVolatilityAt(closes, index, 90)));

            BigDecimal dailyReturn = null;
            if (index > 0) {
                dailyReturn = percentChange(closes.get(index - 1), closes.get(index));
            }
            row.setDailyReturnPercent(scaleNullable(dailyReturn));
        }
    }

    private StockMetrics buildMetrics(Long stockId, List<StockMarketData> historyAsc) {
        StockMarketData latest = historyAsc.get(historyAsc.size() - 1);
        List<BigDecimal> closes = historyAsc.stream().map(StockMarketData::getClosePrice).toList();
        List<Long> volumes = historyAsc.stream().map(StockMarketData::getVolume).toList();

        BigDecimal weekReturn = computeReturn(closes, ONE_WEEK_PERIODS);
        BigDecimal monthReturn = computeReturn(closes, ONE_MONTH_PERIODS);
        BigDecimal threeMonthReturn = computeReturn(closes, THREE_MONTH_PERIODS);
        BigDecimal sixMonthReturn = computeReturn(closes, SIX_MONTH_PERIODS);
        BigDecimal yearReturn = computeReturn(closes, ONE_YEAR_PERIODS);
        BigDecimal threeYearReturn = computeReturn(closes, THREE_YEAR_PERIODS);
        BigDecimal high52w = maxHigh(historyAsc, ONE_YEAR_PERIODS);
        BigDecimal low52w = minLow(historyAsc, ONE_YEAR_PERIODS);
        BigDecimal currentPrice = latest.getClosePrice();
        BigDecimal distanceFromHighPercent = percentDistance(currentPrice, high52w);
        BigDecimal distanceFromLowPercent = percentDistance(currentPrice, low52w);
        BigDecimal average30DayVolume = averageVolume(volumes, 30);
        Long latestTradingDayVolume = latest.getVolume();
        BigDecimal relativeVolume = latestTradingDayVolume == null
                || average30DayVolume == null
                || average30DayVolume.compareTo(BigDecimal.ZERO) == 0
                ? null
                : BigDecimal.valueOf(latestTradingDayVolume).divide(average30DayVolume, MATH_CONTEXT);
        BigDecimal volatility30d = computeAnnualizedVolatility(closes, 30);
        BigDecimal volatility90d = computeAnnualizedVolatility(closes, 90);
        int[] distribution = computeDistribution(historyAsc, ONE_YEAR_PERIODS);
        DrawdownSummary drawdownSummary = computeDrawdownSummary(historyAsc);
        RiskSummary riskSummary = computeRiskSummary(closes);
        BigDecimal rsi14 = computeRsi(closes, 14);
        MacdResult macdResult = computeMacd(closes);
        BigDecimal momentum30d = computeReturn(closes, 30);
        BigDecimal sma50 = simpleMovingAverage(closes, 50);
        BigDecimal sma200 = simpleMovingAverage(closes, 200);
        Boolean goldenCross = sma50 != null && sma200 != null ? sma50.compareTo(sma200) > 0 : null;
        Boolean deathCross = sma50 != null && sma200 != null ? sma50.compareTo(sma200) < 0 : null;
        String monthlyReturnsJson = serializeMonthlyReturnsHeatmap(historyAsc);

        StockMetrics row = new StockMetrics();
        row.setStockId(stockId);
        row.setWeekReturn(scaleNullable(weekReturn));
        row.setMonthReturn(scaleNullable(monthReturn));
        row.setThreeMonthReturn(scaleNullable(threeMonthReturn));
        row.setSixMonthReturn(scaleNullable(sixMonthReturn));
        row.setYearReturn(scaleNullable(yearReturn));
        row.setThreeYearReturn(scaleNullable(threeYearReturn));
        row.setHigh52w(scaleNullable(high52w));
        row.setLow52w(scaleNullable(low52w));
        row.setDistanceFromHighPercent(scaleNullable(distanceFromHighPercent));
        row.setDistanceFromLowPercent(scaleNullable(distanceFromLowPercent));
        row.setAvgVolume30d(scaleNullable(average30DayVolume));
        row.setLatestTradingDayVolume(latestTradingDayVolume);
        row.setLatestTradingDate(latest.getTradingDate());
        row.setRelativeVolume(scaleNullable(relativeVolume));
        row.setVolatility30d(scaleNullable(volatility30d));
        row.setVolatility90d(scaleNullable(volatility90d));
        row.setPositiveDays1y(distribution[0]);
        row.setNegativeDays1y(distribution[1]);
        row.setFlatDays1y(distribution[2]);
        row.setMonthlyReturnsHeatmap(monthlyReturnsJson);
        row.setMaxDrawdown(scaleNullable(drawdownSummary.maxDrawdown()));
        row.setDrawdownPeakDate(drawdownSummary.peakDate());
        row.setDrawdownTroughDate(drawdownSummary.troughDate());
        row.setSharpeRatio(scaleNullable(riskSummary.sharpeRatio()));
        row.setSortinoRatio(scaleNullable(riskSummary.sortinoRatio()));
        row.setRsi14(scaleNullable(rsi14));
        row.setMacd(scaleNullable(macdResult.macd()));
        row.setMacdSignal(scaleNullable(macdResult.signal()));
        row.setMomentum30d(scaleNullable(momentum30d));
        row.setGoldenCross(goldenCross);
        row.setDeathCross(deathCross);
        return row;
    }

    /** Returns [positiveDays, negativeDays, flatDays] for up to the last {@code periods} trading rows. */
    private int[] computeDistribution(List<StockMarketData> historyAsc, int periods) {
        int size = historyAsc.size();
        int start = Math.max(1, size - periods);
        int positive = 0, negative = 0, flat = 0;
        for (int i = start; i < size; i++) {
            BigDecimal prev = historyAsc.get(i - 1).getClosePrice();
            BigDecimal curr = historyAsc.get(i).getClosePrice();
            if (prev == null || curr == null) continue;
            int cmp = curr.compareTo(prev);
            if (cmp > 0) positive++;
            else if (cmp < 0) negative++;
            else flat++;
        }
        return new int[]{positive, negative, flat};
    }

    private BigDecimal computeReturn(List<BigDecimal> closes, int lookbackPeriods) {
        int size = closes.size();
        if (size <= lookbackPeriods) {
            return null;
        }

        BigDecimal latest = closes.get(size - 1);
        BigDecimal baseline = closes.get(size - 1 - lookbackPeriods);
        if (baseline == null || baseline.compareTo(BigDecimal.ZERO) == 0 || latest == null) {
            return null;
        }
        return latest.divide(baseline, MATH_CONTEXT).subtract(BigDecimal.ONE).multiply(HUNDRED, MATH_CONTEXT);
    }

    private BigDecimal percentDistance(BigDecimal current, BigDecimal anchor) {
        if (current == null || anchor == null || anchor.compareTo(ZERO) == 0) {
            return null;
        }
        return current.subtract(anchor).divide(anchor, MATH_CONTEXT).multiply(HUNDRED, MATH_CONTEXT);
    }

    private BigDecimal maxHigh(List<StockMarketData> historyAsc, int periods) {
        int size = historyAsc.size();
        int from = Math.max(0, size - periods);
        BigDecimal max = null;
        for (int i = from; i < size; i++) {
            BigDecimal high = historyAsc.get(i).getHighPrice();
            if (high == null) {
                continue;
            }
            if (max == null || high.compareTo(max) > 0) {
                max = high;
            }
        }
        return max;
    }

    private BigDecimal minLow(List<StockMarketData> historyAsc, int periods) {
        int size = historyAsc.size();
        int from = Math.max(0, size - periods);
        BigDecimal min = null;
        for (int i = from; i < size; i++) {
            BigDecimal low = historyAsc.get(i).getLowPrice();
            if (low == null) {
                continue;
            }
            if (min == null || low.compareTo(min) < 0) {
                min = low;
            }
        }
        return min;
    }

    private BigDecimal averageVolume(List<Long> volumes, int periods) {
        if (volumes.isEmpty()) {
            return null;
        }

        int size = volumes.size();
        int from = Math.max(0, size - periods);
        long count = 0L;
        BigDecimal sum = BigDecimal.ZERO;
        for (int i = from; i < size; i++) {
            Long volume = volumes.get(i);
            if (volume == null) {
                continue;
            }
            sum = sum.add(BigDecimal.valueOf(volume));
            count++;
        }
        if (count == 0L) {
            return null;
        }
        return sum.divide(BigDecimal.valueOf(count), MATH_CONTEXT);
    }

    private BigDecimal computeAnnualizedVolatility(List<BigDecimal> closes, int periods) {
        List<Double> returns = dailyReturns(closes, periods);
        if (returns.size() < 2) {
            return null;
        }

        double mean = returns.stream().mapToDouble(Double::doubleValue).average().orElse(0.0d);
        double sumSquaredDiff = 0.0d;
        for (double value : returns) {
            double delta = value - mean;
            sumSquaredDiff += delta * delta;
        }

        double variance = sumSquaredDiff / (returns.size() - 1);
        double stdDev = Math.sqrt(variance);
        return BigDecimal.valueOf(stdDev * SQRT_252 * 100.0d);
    }

    private BigDecimal computeAnnualizedVolatilityAt(List<BigDecimal> closes, int inclusiveIndex, int periods) {
        if (inclusiveIndex < periods) {
            return null;
        }
        List<BigDecimal> subset = closes.subList(0, inclusiveIndex + 1);
        return computeAnnualizedVolatility(subset, periods);
    }

    private DrawdownSummary computeDrawdownSummary(List<StockMarketData> historyAsc) {
        BigDecimal runningPeak = null;
        LocalDate runningPeakDate = null;
        BigDecimal maxDrawdown = BigDecimal.ZERO;
        LocalDate peakDate = null;
        LocalDate troughDate = null;

        for (StockMarketData point : historyAsc) {
            if (point.getClosePrice() == null || point.getTradingDate() == null) {
                continue;
            }

            if (runningPeak == null || point.getClosePrice().compareTo(runningPeak) > 0) {
                runningPeak = point.getClosePrice();
                runningPeakDate = point.getTradingDate();
                continue;
            }

            BigDecimal drawdown = point.getClosePrice()
                    .subtract(runningPeak)
                    .divide(runningPeak, MATH_CONTEXT)
                    .multiply(HUNDRED, MATH_CONTEXT);
            if (drawdown.compareTo(maxDrawdown) < 0) {
                maxDrawdown = drawdown;
                peakDate = runningPeakDate;
                troughDate = point.getTradingDate();
            }
        }

        return new DrawdownSummary(maxDrawdown, peakDate, troughDate);
    }

    private List<Double> dailyReturns(List<BigDecimal> closes, int periods) {
        int size = closes.size();
        if (size < periods + 1) {
            return List.of();
        }

        int start = size - (periods + 1);
        List<Double> values = new ArrayList<>(periods);
        for (int i = start + 1; i < size; i++) {
            BigDecimal prev = closes.get(i - 1);
            BigDecimal current = closes.get(i);
            if (prev == null || current == null || prev.compareTo(BigDecimal.ZERO) == 0) {
                continue;
            }
            double ret = current.subtract(prev).divide(prev, MATH_CONTEXT).doubleValue();
            values.add(ret);
        }
        return values;
    }

    private RiskSummary computeRiskSummary(List<BigDecimal> closes) {
        List<Double> returns = dailyReturns(closes, ONE_YEAR_PERIODS);
        if (returns.size() < 2) {
            return new RiskSummary(null, null);
        }

        double mean = returns.stream().mapToDouble(Double::doubleValue).average().orElse(0.0d);
        double stdDev = standardDeviation(returns, mean);
        BigDecimal sharpe = stdDev == 0.0d ? null : BigDecimal.valueOf((mean / stdDev) * SQRT_252);

        List<Double> downside = returns.stream().filter(value -> value < 0.0d).toList();
        BigDecimal sortino = null;
        if (!downside.isEmpty()) {
            double downsideMean = downside.stream().mapToDouble(Double::doubleValue).average().orElse(0.0d);
            double downsideStdDev = standardDeviation(downside, downsideMean);
            if (downsideStdDev != 0.0d) {
                sortino = BigDecimal.valueOf((mean / downsideStdDev) * SQRT_252);
            }
        }

        return new RiskSummary(sharpe, sortino);
    }

    private double standardDeviation(List<Double> values, double mean) {
        if (values.size() < 2) {
            return 0.0d;
        }
        double squaredDiff = 0.0d;
        for (double value : values) {
            double delta = value - mean;
            squaredDiff += delta * delta;
        }
        return Math.sqrt(squaredDiff / (values.size() - 1));
    }

    private BigDecimal simpleMovingAverage(List<BigDecimal> closes, int periods) {
        if (closes.size() < periods) {
            return null;
        }
        BigDecimal sum = BigDecimal.ZERO;
        int start = closes.size() - periods;
        for (int index = start; index < closes.size(); index++) {
            BigDecimal close = closes.get(index);
            if (close == null) {
                return null;
            }
            sum = sum.add(close);
        }
        return sum.divide(BigDecimal.valueOf(periods), MATH_CONTEXT);
    }

    private BigDecimal simpleMovingAverageAt(List<BigDecimal> closes, int inclusiveIndex, int periods) {
        if (inclusiveIndex + 1 < periods) {
            return null;
        }
        BigDecimal sum = BigDecimal.ZERO;
        for (int index = inclusiveIndex - periods + 1; index <= inclusiveIndex; index++) {
            BigDecimal close = closes.get(index);
            if (close == null) {
                return null;
            }
            sum = sum.add(close);
        }
        return sum.divide(BigDecimal.valueOf(periods), MATH_CONTEXT);
    }

    private BigDecimal computeRsi(List<BigDecimal> closes, int periods) {
        if (closes.size() < periods + 1) {
            return null;
        }
        BigDecimal gainSum = BigDecimal.ZERO;
        BigDecimal lossSum = BigDecimal.ZERO;
        int start = closes.size() - (periods + 1);
        for (int index = start + 1; index < closes.size(); index++) {
            BigDecimal previous = closes.get(index - 1);
            BigDecimal current = closes.get(index);
            if (previous == null || current == null) {
                return null;
            }
            BigDecimal delta = current.subtract(previous);
            if (delta.compareTo(BigDecimal.ZERO) >= 0) {
                gainSum = gainSum.add(delta);
            } else {
                lossSum = lossSum.add(delta.abs());
            }
        }
        BigDecimal averageGain = gainSum.divide(BigDecimal.valueOf(periods), MATH_CONTEXT);
        BigDecimal averageLoss = lossSum.divide(BigDecimal.valueOf(periods), MATH_CONTEXT);
        if (averageLoss.compareTo(BigDecimal.ZERO) == 0) {
            return BigDecimal.valueOf(100);
        }
        BigDecimal rs = averageGain.divide(averageLoss, MATH_CONTEXT);
        return HUNDRED.subtract(HUNDRED.divide(BigDecimal.ONE.add(rs), MATH_CONTEXT));
    }

    private MacdResult computeMacd(List<BigDecimal> closes) {
        if (closes.size() < 26) {
            return new MacdResult(null, null);
        }
        List<Double> closeValues = closes.stream()
                .map(value -> value == null ? null : value.doubleValue())
                .filter(java.util.Objects::nonNull)
                .toList();
        if (closeValues.size() < 26) {
            return new MacdResult(null, null);
        }

        List<Double> ema12 = emaSeries(closeValues, 12);
        List<Double> ema26 = emaSeries(closeValues, 26);
        List<Double> macdSeries = new ArrayList<>();
        for (int index = 0; index < closeValues.size(); index++) {
            Double shortValue = ema12.get(index);
            Double longValue = ema26.get(index);
            macdSeries.add(shortValue == null || longValue == null ? null : shortValue - longValue);
        }

        List<Double> compactMacd = macdSeries.stream().filter(java.util.Objects::nonNull).toList();
        if (compactMacd.isEmpty()) {
            return new MacdResult(null, null);
        }
        List<Double> signalSeries = emaSeries(compactMacd, 9);
        Double macd = compactMacd.get(compactMacd.size() - 1);
        Double signal = signalSeries.get(signalSeries.size() - 1);
        return new MacdResult(BigDecimal.valueOf(macd), signal == null ? null : BigDecimal.valueOf(signal));
    }

    private List<Double> emaSeries(List<Double> values, int periods) {
        List<Double> ema = new ArrayList<>(values.size());
        double multiplier = 2.0d / (periods + 1.0d);
        Double previous = null;
        for (Double value : values) {
            if (value == null) {
                ema.add(null);
                continue;
            }
            if (previous == null) {
                previous = value;
            } else {
                previous = ((value - previous) * multiplier) + previous;
            }
            ema.add(previous);
        }
        return ema;
    }

    private BigDecimal scale(BigDecimal value) {
        return value.setScale(2, RoundingMode.HALF_UP);
    }

    private BigDecimal scaleNullable(BigDecimal value) {
        return value == null ? null : scale(value);
    }

    /** Computes and serializes monthly returns heatmap as JSON. */
    private String serializeMonthlyReturnsHeatmap(List<StockMarketData> historyAsc) {
        try {
            Map<YearMonth, BigDecimal> monthCloseMap = new LinkedHashMap<>();
            for (StockMarketData point : historyAsc) {
                if (point.getTradingDate() == null || point.getClosePrice() == null) {
                    continue;
                }
                monthCloseMap.put(YearMonth.from(point.getTradingDate()), point.getClosePrice());
            }

            List<Map.Entry<YearMonth, BigDecimal>> monthlyEntries = new ArrayList<>(monthCloseMap.entrySet());
            List<Map<String, Object>> cells = new ArrayList<>();
            for (int index = 1; index < monthlyEntries.size(); index++) {
                Map.Entry<YearMonth, BigDecimal> current = monthlyEntries.get(index);
                Map.Entry<YearMonth, BigDecimal> previous = monthlyEntries.get(index - 1);
                BigDecimal monthlyReturn = percentChange(previous.getValue(), current.getValue());

                Map<String, Object> cell = new LinkedHashMap<>();
                cell.put("year", current.getKey().getYear());
                cell.put("month", current.getKey().getMonthValue());
                cell.put("returnPercent", monthlyReturn == null ? null : monthlyReturn.setScale(2, RoundingMode.HALF_UP).doubleValue());
                cells.add(cell);
            }

            ObjectMapper mapper = new ObjectMapper();
            return mapper.writeValueAsString(cells);
        } catch (Exception e) {
            log.warn("Failed to serialize monthly returns heatmap: {}", e.getMessage());
            return null;
        }
    }

    private BigDecimal percentChange(BigDecimal baseline, BigDecimal current) {
        if (baseline == null || current == null || baseline.compareTo(ZERO) == 0) {
            return null;
        }
        return current.subtract(baseline).divide(baseline, MATH_CONTEXT).multiply(BigDecimal.valueOf(100), MATH_CONTEXT);
    }

    private record DrawdownSummary(BigDecimal maxDrawdown, LocalDate peakDate, LocalDate troughDate) {
    }

    private record RiskSummary(BigDecimal sharpeRatio, BigDecimal sortinoRatio) {
    }

    private record MacdResult(BigDecimal macd, BigDecimal signal) {
    }

}

package com.tradepulseai.stockservice.service;

import com.tradepulseai.stockservice.model.Stock;
import com.tradepulseai.stockservice.model.StockMarketData;
import com.tradepulseai.stockservice.model.StockMetrics;
import com.tradepulseai.stockservice.repository.StockMarketDataRepository;
import com.tradepulseai.stockservice.repository.StockMetricsRepository;
import com.tradepulseai.stockservice.repository.StockRepository;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.data.domain.PageRequest;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.math.BigDecimal;
import java.math.MathContext;
import java.math.RoundingMode;
import java.time.LocalDate;
import java.time.YearMonth;
import java.util.ArrayList;
import java.util.Comparator;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import com.fasterxml.jackson.databind.ObjectMapper;

@Service
public class StockMetricsRefreshService {

    private static final Logger log = LoggerFactory.getLogger(StockMetricsRefreshService.class);
    private static final int LOOKBACK_ROWS = 800;
    private static final int ONE_WEEK_PERIODS = 5;
    private static final int ONE_MONTH_PERIODS = 21;
    private static final int THREE_MONTH_PERIODS = 63;
    private static final int SIX_MONTH_PERIODS = 126;
    private static final int ONE_YEAR_PERIODS = 252;
    private static final int THREE_YEAR_PERIODS = 756;
    private static final double SQRT_252 = Math.sqrt(252.0d);
    private static final BigDecimal ZERO = BigDecimal.ZERO;
    private static final MathContext MATH_CONTEXT = new MathContext(12, RoundingMode.HALF_UP);
    private static final BigDecimal HUNDRED = BigDecimal.valueOf(100);

    private final StockRepository stockRepository;
    private final StockMarketDataRepository stockMarketDataRepository;
    private final StockMetricsRepository stockMetricsRepository;

    public StockMetricsRefreshService(
            StockRepository stockRepository,
            StockMarketDataRepository stockMarketDataRepository,
            StockMetricsRepository stockMetricsRepository) {
        this.stockRepository = stockRepository;
        this.stockMarketDataRepository = stockMarketDataRepository;
        this.stockMetricsRepository = stockMetricsRepository;
    }

    @Transactional
    public void refreshAllForLatestOhlc(String trigger) {
        Optional<LocalDate> maxTradingDate = stockMarketDataRepository.findMaxTradingDate();
        if (maxTradingDate.isEmpty()) {
            log.info("Skipping stock metrics refresh ({}) because no OHLC rows exist.", trigger);
            return;
        }

        List<Stock> stocks = stockRepository.findAllByOrderByStockIdAsc();
        if (stocks.isEmpty()) {
            log.info("Skipping stock metrics refresh ({}) because stocks table is empty.", trigger);
            return;
        }

        List<StockMetrics> metricsRows = new ArrayList<>();
        List<StockMarketData> indicatorRows = new ArrayList<>();
        for (Stock stock : stocks) {
            Long stockId = stock.getStockId();
            if (stockId == null) {
                continue;
            }

            List<StockMarketData> historyDesc = stockMarketDataRepository.findRecentByStockId(stockId, PageRequest.of(0, LOOKBACK_ROWS));
            if (historyDesc.isEmpty()) {
                continue;
            }

            historyDesc.sort(Comparator.comparing(StockMarketData::getTradingDate));
            applyIndicatorsToHistory(historyDesc);
            indicatorRows.addAll(historyDesc);
            StockMetrics metrics = buildMetrics(stockId, historyDesc);
            metricsRows.add(metrics);
        }

        if (metricsRows.isEmpty()) {
            log.info("Stock metrics refresh ({}) found no computable rows.", trigger);
            return;
        }

        stockMarketDataRepository.saveAll(indicatorRows);
        stockMetricsRepository.saveAll(metricsRows);
        log.info("Stock metrics refresh ({}) upserted {} rows for latest OHLC date {}.",
                trigger, metricsRows.size(), maxTradingDate.get());
    }

    private void applyIndicatorsToHistory(List<StockMarketData> historyAsc) {
        List<BigDecimal> closes = historyAsc.stream().map(StockMarketData::getClosePrice).toList();

        // Pre-compute RSI and MACD per-row using EMA series over all closes
        List<Double> closeDoubles = closes.stream()
                .map(v -> v == null ? null : v.doubleValue())
                .filter(java.util.Objects::nonNull)
                .toList();
        List<Double> ema12Series = emaSeries(closeDoubles, 12);
        List<Double> ema26Series = emaSeries(closeDoubles, 26);
        List<Double> macdSeries = new ArrayList<>();
        for (int i = 0; i < closeDoubles.size(); i++) {
            Double e12 = ema12Series.get(i);
            Double e26 = ema26Series.get(i);
            macdSeries.add(e12 == null || e26 == null ? null : e12 - e26);
        }
        List<Double> signalSeries = emaSeries(
                macdSeries.stream().filter(java.util.Objects::nonNull).toList(), 9);

        for (int index = 0; index < historyAsc.size(); index++) {
            StockMarketData row = historyAsc.get(index);
            row.setSma20(scaleNullable(simpleMovingAverageAt(closes, index, 20)));
            row.setSma50(scaleNullable(simpleMovingAverageAt(closes, index, 50)));
            row.setSma200(scaleNullable(simpleMovingAverageAt(closes, index, 200)));
            row.setVolatility30d(scaleNullable(computeAnnualizedVolatilityAt(closes, index, 30)));
            row.setVolatility90d(scaleNullable(computeAnnualizedVolatilityAt(closes, index, 90)));

            BigDecimal dailyReturn = null;
            if (index > 0) {
                dailyReturn = percentChange(closes.get(index - 1), closes.get(index));
            }
            row.setDailyReturnPercent(scaleNullable(dailyReturn));

            // 5-day return
            BigDecimal return5d = index >= 5
                    ? percentChange(closes.get(index - 5), closes.get(index)) : null;
            row.setReturn5d(return5d == null ? null : return5d.setScale(4, RoundingMode.HALF_UP));

            // 20-day momentum (same as 20-day return expressed as % change)
            BigDecimal momentum20d = index >= 20
                    ? percentChange(closes.get(index - 20), closes.get(index)) : null;
            row.setMomentum20d(momentum20d == null ? null : momentum20d.setScale(4, RoundingMode.HALF_UP));

            // RSI 14 using a rolling window up to this index
            BigDecimal rsi14 = computeRsi(closes.subList(0, index + 1), 14);
            row.setRsi14(scaleNullable4(rsi14));

            // MACD and signal from pre-computed series
            if (index < macdSeries.size() && macdSeries.get(index) != null) {
                row.setMacd(BigDecimal.valueOf(macdSeries.get(index)).setScale(4, RoundingMode.HALF_UP));
            }
            // Signal aligns with compacted macd series index, approximate by using signalSeries at same position
            long nonNullBefore = macdSeries.subList(0, index + 1).stream().filter(java.util.Objects::nonNull).count();
            if (nonNullBefore > 0 && nonNullBefore - 1 < signalSeries.size()) {
                Double sig = signalSeries.get((int) nonNullBefore - 1);
                if (sig != null) {
                    row.setMacdSignal(BigDecimal.valueOf(sig).setScale(4, RoundingMode.HALF_UP));
                }
            }
        }
    }

    private BigDecimal scaleNullable4(BigDecimal value) {
        return value == null ? null : value.setScale(4, RoundingMode.HALF_UP);
    }

    private StockMetrics buildMetrics(Long stockId, List<StockMarketData> historyAsc) {
        StockMarketData latest = historyAsc.get(historyAsc.size() - 1);
        List<BigDecimal> closes = historyAsc.stream().map(StockMarketData::getClosePrice).toList();
        List<Long> volumes = historyAsc.stream().map(StockMarketData::getVolume).toList();

        BigDecimal weekReturn = computeReturn(closes, ONE_WEEK_PERIODS);
        BigDecimal monthReturn = computeReturn(closes, ONE_MONTH_PERIODS);
        BigDecimal threeMonthReturn = computeReturn(closes, THREE_MONTH_PERIODS);
        BigDecimal sixMonthReturn = computeReturn(closes, SIX_MONTH_PERIODS);
        BigDecimal yearReturn = computeReturn(closes, ONE_YEAR_PERIODS);
        BigDecimal threeYearReturn = computeReturn(closes, THREE_YEAR_PERIODS);
        BigDecimal high52w = maxHigh(historyAsc, ONE_YEAR_PERIODS);
        BigDecimal low52w = minLow(historyAsc, ONE_YEAR_PERIODS);
        BigDecimal currentPrice = latest.getClosePrice();
        BigDecimal distanceFromHighPercent = percentDistance(currentPrice, high52w);
        BigDecimal distanceFromLowPercent = percentDistance(currentPrice, low52w);
        BigDecimal average30DayVolume = averageVolume(volumes, 30);
        Long latestTradingDayVolume = latest.getVolume();
        BigDecimal relativeVolume = latestTradingDayVolume == null
                || average30DayVolume == null
                || average30DayVolume.compareTo(BigDecimal.ZERO) == 0
                ? null
                : BigDecimal.valueOf(latestTradingDayVolume).divide(average30DayVolume, MATH_CONTEXT);
        BigDecimal volatility30d = computeAnnualizedVolatility(closes, 30);
        BigDecimal volatility90d = computeAnnualizedVolatility(closes, 90);
        int[] distribution = computeDistribution(historyAsc, ONE_YEAR_PERIODS);
        DrawdownSummary drawdownSummary = computeDrawdownSummary(historyAsc);
        RiskSummary riskSummary = computeRiskSummary(closes);
        BigDecimal rsi14 = computeRsi(closes, 14);
        MacdResult macdResult = computeMacd(closes);
        BigDecimal momentum30d = computeReturn(closes, 30);
        BigDecimal sma50 = simpleMovingAverage(closes, 50);
        BigDecimal sma200 = simpleMovingAverage(closes, 200);
        Boolean goldenCross = sma50 != null && sma200 != null ? sma50.compareTo(sma200) > 0 : null;
        Boolean deathCross = sma50 != null && sma200 != null ? sma50.compareTo(sma200) < 0 : null;
        String monthlyReturnsJson = serializeMonthlyReturnsHeatmap(historyAsc);

        StockMetrics row = new StockMetrics();
        row.setStockId(stockId);
        row.setWeekReturn(scaleNullable(weekReturn));
        row.setMonthReturn(scaleNullable(monthReturn));
        row.setThreeMonthReturn(scaleNullable(threeMonthReturn));
        row.setSixMonthReturn(scaleNullable(sixMonthReturn));
        row.setYearReturn(scaleNullable(yearReturn));
        row.setThreeYearReturn(scaleNullable(threeYearReturn));
        row.setHigh52w(scaleNullable(high52w));
        row.setLow52w(scaleNullable(low52w));
        row.setDistanceFromHighPercent(scaleNullable(distanceFromHighPercent));
        row.setDistanceFromLowPercent(scaleNullable(distanceFromLowPercent));
        row.setAvgVolume30d(scaleNullable(average30DayVolume));
        row.setLatestTradingDayVolume(latestTradingDayVolume);
        row.setLatestTradingDate(latest.getTradingDate());
        row.setRelativeVolume(scaleNullable(relativeVolume));
        row.setVolatility30d(scaleNullable(volatility30d));
        row.setVolatility90d(scaleNullable(volatility90d));
        row.setPositiveDays1y(distribution[0]);
        row.setNegativeDays1y(distribution[1]);
        row.setFlatDays1y(distribution[2]);
        row.setMonthlyReturnsHeatmap(monthlyReturnsJson);
        row.setMaxDrawdown(scaleNullable(drawdownSummary.maxDrawdown()));
        row.setDrawdownPeakDate(drawdownSummary.peakDate());
        row.setDrawdownTroughDate(drawdownSummary.troughDate());
        row.setSharpeRatio(scaleNullable(riskSummary.sharpeRatio()));
        row.setSortinoRatio(scaleNullable(riskSummary.sortinoRatio()));
        row.setRsi14(scaleNullable(rsi14));
        row.setMacd(scaleNullable(macdResult.macd()));
        row.setMacdSignal(scaleNullable(macdResult.signal()));
        row.setMomentum30d(scaleNullable(momentum30d));
        row.setGoldenCross(goldenCross);
        row.setDeathCross(deathCross);
        return row;
    }

    /** Returns [positiveDays, negativeDays, flatDays] for up to the last {@code periods} trading rows. */
    private int[] computeDistribution(List<StockMarketData> historyAsc, int periods) {
        int size = historyAsc.size();
        int start = Math.max(1, size - periods);
        int positive = 0, negative = 0, flat = 0;
        for (int i = start; i < size; i++) {
            BigDecimal prev = historyAsc.get(i - 1).getClosePrice();
            BigDecimal curr = historyAsc.get(i).getClosePrice();
            if (prev == null || curr == null) continue;
            int cmp = curr.compareTo(prev);
            if (cmp > 0) positive++;
            else if (cmp < 0) negative++;
            else flat++;
        }
        return new int[]{positive, negative, flat};
    }

    private BigDecimal computeReturn(List<BigDecimal> closes, int lookbackPeriods) {
        int size = closes.size();
        if (size <= lookbackPeriods) {
            return null;
        }

        BigDecimal latest = closes.get(size - 1);
        BigDecimal baseline = closes.get(size - 1 - lookbackPeriods);
        if (baseline == null || baseline.compareTo(BigDecimal.ZERO) == 0 || latest == null) {
            return null;
        }
        return latest.divide(baseline, MATH_CONTEXT).subtract(BigDecimal.ONE).multiply(HUNDRED, MATH_CONTEXT);
    }

    private BigDecimal percentDistance(BigDecimal current, BigDecimal anchor) {
        if (current == null || anchor == null || anchor.compareTo(ZERO) == 0) {
            return null;
        }
        return current.subtract(anchor).divide(anchor, MATH_CONTEXT).multiply(HUNDRED, MATH_CONTEXT);
    }

    private BigDecimal maxHigh(List<StockMarketData> historyAsc, int periods) {
        int size = historyAsc.size();
        int from = Math.max(0, size - periods);
        BigDecimal max = null;
        for (int i = from; i < size; i++) {
            BigDecimal high = historyAsc.get(i).getHighPrice();
            if (high == null) {
                continue;
            }
            if (max == null || high.compareTo(max) > 0) {
                max = high;
            }
        }
        return max;
    }

    private BigDecimal minLow(List<StockMarketData> historyAsc, int periods) {
        int size = historyAsc.size();
        int from = Math.max(0, size - periods);
        BigDecimal min = null;
        for (int i = from; i < size; i++) {
            BigDecimal low = historyAsc.get(i).getLowPrice();
            if (low == null) {
                continue;
            }
            if (min == null || low.compareTo(min) < 0) {
                min = low;
            }
        }
        return min;
    }

    private BigDecimal averageVolume(List<Long> volumes, int periods) {
        if (volumes.isEmpty()) {
            return null;
        }

        int size = volumes.size();
        int from = Math.max(0, size - periods);
        long count = 0L;
        BigDecimal sum = BigDecimal.ZERO;
        for (int i = from; i < size; i++) {
            Long volume = volumes.get(i);
            if (volume == null) {
                continue;
            }
            sum = sum.add(BigDecimal.valueOf(volume));
            count++;
        }
        if (count == 0L) {
            return null;
        }
        return sum.divide(BigDecimal.valueOf(count), MATH_CONTEXT);
    }

    private BigDecimal computeAnnualizedVolatility(List<BigDecimal> closes, int periods) {
        List<Double> returns = dailyReturns(closes, periods);
        if (returns.size() < 2) {
            return null;
        }

        double mean = returns.stream().mapToDouble(Double::doubleValue).average().orElse(0.0d);
        double sumSquaredDiff = 0.0d;
        for (double value : returns) {
            double delta = value - mean;
            sumSquaredDiff += delta * delta;
        }

        double variance = sumSquaredDiff / (returns.size() - 1);
        double stdDev = Math.sqrt(variance);
        return BigDecimal.valueOf(stdDev * SQRT_252 * 100.0d);
    }

    private BigDecimal computeAnnualizedVolatilityAt(List<BigDecimal> closes, int inclusiveIndex, int periods) {
        if (inclusiveIndex < periods) {
            return null;
        }
        List<BigDecimal> subset = closes.subList(0, inclusiveIndex + 1);
        return computeAnnualizedVolatility(subset, periods);
    }

    private DrawdownSummary computeDrawdownSummary(List<StockMarketData> historyAsc) {
        BigDecimal runningPeak = null;
        LocalDate runningPeakDate = null;
        BigDecimal maxDrawdown = BigDecimal.ZERO;
        LocalDate peakDate = null;
        LocalDate troughDate = null;

        for (StockMarketData point : historyAsc) {
            if (point.getClosePrice() == null || point.getTradingDate() == null) {
                continue;
            }

            if (runningPeak == null || point.getClosePrice().compareTo(runningPeak) > 0) {
                runningPeak = point.getClosePrice();
                runningPeakDate = point.getTradingDate();
                continue;
            }

            BigDecimal drawdown = point.getClosePrice()
                    .subtract(runningPeak)
                    .divide(runningPeak, MATH_CONTEXT)
                    .multiply(HUNDRED, MATH_CONTEXT);
            if (drawdown.compareTo(maxDrawdown) < 0) {
                maxDrawdown = drawdown;
                peakDate = runningPeakDate;
                troughDate = point.getTradingDate();
            }
        }

        return new DrawdownSummary(maxDrawdown, peakDate, troughDate);
    }

    private List<Double> dailyReturns(List<BigDecimal> closes, int periods) {
        int size = closes.size();
        if (size < periods + 1) {
            return List.of();
        }

        int start = size - (periods + 1);
        List<Double> values = new ArrayList<>(periods);
        for (int i = start + 1; i < size; i++) {
            BigDecimal prev = closes.get(i - 1);
            BigDecimal current = closes.get(i);
            if (prev == null || current == null || prev.compareTo(BigDecimal.ZERO) == 0) {
                continue;
            }
            double ret = current.subtract(prev).divide(prev, MATH_CONTEXT).doubleValue();
            values.add(ret);
        }
        return values;
    }

    private RiskSummary computeRiskSummary(List<BigDecimal> closes) {
        List<Double> returns = dailyReturns(closes, ONE_YEAR_PERIODS);
        if (returns.size() < 2) {
            return new RiskSummary(null, null);
        }

        double mean = returns.stream().mapToDouble(Double::doubleValue).average().orElse(0.0d);
        double stdDev = standardDeviation(returns, mean);
        BigDecimal sharpe = stdDev == 0.0d ? null : BigDecimal.valueOf((mean / stdDev) * SQRT_252);

        List<Double> downside = returns.stream().filter(value -> value < 0.0d).toList();
        BigDecimal sortino = null;
        if (!downside.isEmpty()) {
            double downsideMean = downside.stream().mapToDouble(Double::doubleValue).average().orElse(0.0d);
            double downsideStdDev = standardDeviation(downside, downsideMean);
            if (downsideStdDev != 0.0d) {
                sortino = BigDecimal.valueOf((mean / downsideStdDev) * SQRT_252);
            }
        }

        return new RiskSummary(sharpe, sortino);
    }

    private double standardDeviation(List<Double> values, double mean) {
        if (values.size() < 2) {
            return 0.0d;
        }
        double squaredDiff = 0.0d;
        for (double value : values) {
            double delta = value - mean;
            squaredDiff += delta * delta;
        }
        return Math.sqrt(squaredDiff / (values.size() - 1));
    }

    private BigDecimal simpleMovingAverage(List<BigDecimal> closes, int periods) {
        if (closes.size() < periods) {
            return null;
        }
        BigDecimal sum = BigDecimal.ZERO;
        int start = closes.size() - periods;
        for (int index = start; index < closes.size(); index++) {
            BigDecimal close = closes.get(index);
            if (close == null) {
                return null;
            }
            sum = sum.add(close);
        }
        return sum.divide(BigDecimal.valueOf(periods), MATH_CONTEXT);
    }

    private BigDecimal simpleMovingAverageAt(List<BigDecimal> closes, int inclusiveIndex, int periods) {
        if (inclusiveIndex + 1 < periods) {
            return null;
        }
        BigDecimal sum = BigDecimal.ZERO;
        for (int index = inclusiveIndex - periods + 1; index <= inclusiveIndex; index++) {
            BigDecimal close = closes.get(index);
            if (close == null) {
                return null;
            }
            sum = sum.add(close);
        }
        return sum.divide(BigDecimal.valueOf(periods), MATH_CONTEXT);
    }

    private BigDecimal computeRsi(List<BigDecimal> closes, int periods) {
        if (closes.size() < periods + 1) {
            return null;
        }
        BigDecimal gainSum = BigDecimal.ZERO;
        BigDecimal lossSum = BigDecimal.ZERO;
        int start = closes.size() - (periods + 1);
        for (int index = start + 1; index < closes.size(); index++) {
            BigDecimal previous = closes.get(index - 1);
            BigDecimal current = closes.get(index);
            if (previous == null || current == null) {
                return null;
            }
            BigDecimal delta = current.subtract(previous);
            if (delta.compareTo(BigDecimal.ZERO) >= 0) {
                gainSum = gainSum.add(delta);
            } else {
                lossSum = lossSum.add(delta.abs());
            }
        }
        BigDecimal averageGain = gainSum.divide(BigDecimal.valueOf(periods), MATH_CONTEXT);
        BigDecimal averageLoss = lossSum.divide(BigDecimal.valueOf(periods), MATH_CONTEXT);
        if (averageLoss.compareTo(BigDecimal.ZERO) == 0) {
            return BigDecimal.valueOf(100);
        }
        BigDecimal rs = averageGain.divide(averageLoss, MATH_CONTEXT);
        return HUNDRED.subtract(HUNDRED.divide(BigDecimal.ONE.add(rs), MATH_CONTEXT));
    }

    private MacdResult computeMacd(List<BigDecimal> closes) {
        if (closes.size() < 26) {
            return new MacdResult(null, null);
        }
        List<Double> closeValues = closes.stream()
                .map(value -> value == null ? null : value.doubleValue())
                .filter(java.util.Objects::nonNull)
                .toList();
        if (closeValues.size() < 26) {
            return new MacdResult(null, null);
        }

        List<Double> ema12 = emaSeries(closeValues, 12);
        List<Double> ema26 = emaSeries(closeValues, 26);
        List<Double> macdSeries = new ArrayList<>();
        for (int index = 0; index < closeValues.size(); index++) {
            Double shortValue = ema12.get(index);
            Double longValue = ema26.get(index);
            macdSeries.add(shortValue == null || longValue == null ? null : shortValue - longValue);
        }

        List<Double> compactMacd = macdSeries.stream().filter(java.util.Objects::nonNull).toList();
        if (compactMacd.isEmpty()) {
            return new MacdResult(null, null);
        }
        List<Double> signalSeries = emaSeries(compactMacd, 9);
        Double macd = compactMacd.get(compactMacd.size() - 1);
        Double signal = signalSeries.get(signalSeries.size() - 1);
        return new MacdResult(BigDecimal.valueOf(macd), signal == null ? null : BigDecimal.valueOf(signal));
    }

    private List<Double> emaSeries(List<Double> values, int periods) {
        List<Double> ema = new ArrayList<>(values.size());
        double multiplier = 2.0d / (periods + 1.0d);
        Double previous = null;
        for (Double value : values) {
            if (value == null) {
                ema.add(null);
                continue;
            }
            if (previous == null) {
                previous = value;
            } else {
                previous = ((value - previous) * multiplier) + previous;
            }
            ema.add(previous);
        }
        return ema;
    }

    private BigDecimal scale(BigDecimal value) {
        return value.setScale(2, RoundingMode.HALF_UP);
    }

    private BigDecimal scaleNullable(BigDecimal value) {
        return value == null ? null : scale(value);
    }

    /** Computes and serializes monthly returns heatmap as JSON. */
    private String serializeMonthlyReturnsHeatmap(List<StockMarketData> historyAsc) {
        try {
            Map<YearMonth, BigDecimal> monthCloseMap = new LinkedHashMap<>();
            for (StockMarketData point : historyAsc) {
                if (point.getTradingDate() == null || point.getClosePrice() == null) {
                    continue;
                }
                monthCloseMap.put(YearMonth.from(point.getTradingDate()), point.getClosePrice());
            }

            List<Map.Entry<YearMonth, BigDecimal>> monthlyEntries = new ArrayList<>(monthCloseMap.entrySet());
            List<Map<String, Object>> cells = new ArrayList<>();
            for (int index = 1; index < monthlyEntries.size(); index++) {
                Map.Entry<YearMonth, BigDecimal> current = monthlyEntries.get(index);
                Map.Entry<YearMonth, BigDecimal> previous = monthlyEntries.get(index - 1);
                BigDecimal monthlyReturn = percentChange(previous.getValue(), current.getValue());

                Map<String, Object> cell = new LinkedHashMap<>();
                cell.put("year", current.getKey().getYear());
                cell.put("month", current.getKey().getMonthValue());
                cell.put("returnPercent", monthlyReturn == null ? null : monthlyReturn.setScale(2, RoundingMode.HALF_UP).doubleValue());
                cells.add(cell);
            }

            ObjectMapper mapper = new ObjectMapper();
            return mapper.writeValueAsString(cells);
        } catch (Exception e) {
            log.warn("Failed to serialize monthly returns heatmap: {}", e.getMessage());
            return null;
        }
    }

    private BigDecimal percentChange(BigDecimal baseline, BigDecimal current) {
        if (baseline == null || current == null || baseline.compareTo(ZERO) == 0) {
            return null;
        }
        return current.subtract(baseline).divide(baseline, MATH_CONTEXT).multiply(BigDecimal.valueOf(100), MATH_CONTEXT);
    }

    private record DrawdownSummary(BigDecimal maxDrawdown, LocalDate peakDate, LocalDate troughDate) {
    }

    private record RiskSummary(BigDecimal sharpeRatio, BigDecimal sortinoRatio) {
    }

    private record MacdResult(BigDecimal macd, BigDecimal signal) {
    }

}

package com.tradepulseai.stockservice.service;

import com.tradepulseai.stockservice.model.Stock;
import com.tradepulseai.stockservice.model.StockMarketData;
import com.tradepulseai.stockservice.repository.StockMarketDataRepository;
import com.tradepulseai.stockservice.repository.StockRepository;
import jakarta.annotation.PreDestroy;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.ApplicationArguments;
import org.springframework.boot.ApplicationRunner;
import org.springframework.core.annotation.Order;
import org.springframework.lang.NonNull;
import org.springframework.stereotype.Component;
import org.springframework.web.client.HttpClientErrorException;
import org.springframework.web.client.RestClient;
import org.springframework.web.util.UriComponentsBuilder;
import tools.jackson.databind.JsonNode;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.DayOfWeek;
import java.time.LocalDate;
import java.time.ZoneId;
import java.util.HashMap;
import java.util.HashSet;
import java.util.List;
import java.util.Locale;
import java.util.Map;
import java.util.Set;
import java.util.concurrent.atomic.AtomicBoolean;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;

@Component
@Order(3)
public class StockOhlcSyncService implements ApplicationRunner {

    private static final Logger log = LoggerFactory.getLogger(StockOhlcSyncService.class);

    private final StockRepository stockRepository;
    private final StockMarketDataRepository stockMarketDataRepository;
    private final StockMetricsRefreshService stockMetricsRefreshService;
    private final RestClient restClient;
    private final String apiKey;
    private final boolean syncOnStartup;
    private final boolean dailySyncEnabled;
    private final int yearsBack;
    private final long refreshInitialDelayMinutes;
    private final long refreshIntervalMinutes;
    private final boolean adjusted;
    private final boolean includeOtc;
    private final ZoneId syncZone;
    private final ScheduledExecutorService refreshExecutor;
    private final AtomicBoolean refreshLoopStarted = new AtomicBoolean(false);
    private final AtomicBoolean running = new AtomicBoolean(false);

    public StockOhlcSyncService(
            StockRepository stockRepository,
            StockMarketDataRepository stockMarketDataRepository,
            StockMetricsRefreshService stockMetricsRefreshService,
            @Value("${massive.api.base-url}") String apiBaseUrl,
            @Value("${massive.api.key:}") String apiKey,
            @Value("${massive.ohlc.sync-on-startup:true}") boolean syncOnStartup,
            @Value("${massive.ohlc.daily-sync-enabled:true}") boolean dailySyncEnabled,
            @Value("${massive.ohlc.years-back:3}") int yearsBack,
            @Value("${massive.ohlc.refresh-initial-delay-minutes:1}") long refreshInitialDelayMinutes,
            @Value("${massive.ohlc.refresh-interval-minutes:30}") long refreshIntervalMinutes,
            @Value("${massive.ohlc.adjusted:true}") boolean adjusted,
            @Value("${massive.ohlc.include-otc:false}") boolean includeOtc,
            @Value("${massive.ohlc.sync-zone:UTC}") String syncZone) {
        this.stockRepository = stockRepository;
        this.stockMarketDataRepository = stockMarketDataRepository;
        this.stockMetricsRefreshService = stockMetricsRefreshService;
        this.apiKey = apiKey;
        this.syncOnStartup = syncOnStartup;
        this.dailySyncEnabled = dailySyncEnabled;
        this.yearsBack = yearsBack;
        this.refreshInitialDelayMinutes = Math.max(1L, refreshInitialDelayMinutes);
        this.refreshIntervalMinutes = Math.max(1L, refreshIntervalMinutes);
        this.adjusted = adjusted;
        this.includeOtc = includeOtc;
        this.syncZone = ZoneId.of(syncZone);
        this.refreshExecutor = Executors.newSingleThreadScheduledExecutor(r -> {
            Thread thread = new Thread(r, "stock-ohlc-refresh");
            thread.setDaemon(true);
            return thread;
        });
        this.restClient = RestClient.builder()
                .baseUrl(apiBaseUrl)
                .build();
    }

    @Override
    public void run(@NonNull ApplicationArguments args) {
        if (syncOnStartup || dailySyncEnabled) {
            ensureApiKeyConfigured();
        }

        if (dailySyncEnabled) {
            startBackgroundRefreshLoop();
        }

        if (syncOnStartup) {
            syncMissingData("startup");
        }
    }

    private void syncMissingData(String trigger) {
        if (!running.compareAndSet(false, true)) {
            log.info("Skipping {} OHLC sync because another sync is already running.", trigger);
            return;
        }

        try {
            if (apiKey == null || apiKey.isBlank()) {
                throw new IllegalStateException("massive.api.key is required for OHLC sync");
            }

            List<Stock> stocks = stockRepository.findAllByOrderByStockIdAsc();
            if (stocks.isEmpty()) {
                log.info("Skipping {} OHLC sync because stocks table is empty.", trigger);
                return;
            }

            Map<String, Stock> stockByTicker = new HashMap<>();
            for (Stock stock : stocks) {
                String symbol = normalize(stock.getSymbol());
                if (symbol != null) {
                    stockByTicker.put(symbol, stock);
                }
            }

            LocalDate endDate = LocalDate.now(syncZone);
            LocalDate configuredStart = endDate.minusYears(yearsBack);
            LocalDate startDate = stockMarketDataRepository.findMaxTradingDate()
                    .map(date -> date.plusDays(1))
                    .orElse(configuredStart);

            if (startDate.isBefore(configuredStart)) {
                startDate = configuredStart;
            }

            if (startDate.isAfter(endDate)) {
                log.info("No missing OHLC dates to sync for trigger {}.", trigger);
                if ("startup".equalsIgnoreCase(trigger)) {
                    stockMetricsRefreshService.refreshAllForLatestOhlc(trigger);
                }
                return;
            }

            int totalInserted = 0;
            for (LocalDate date = startDate; !date.isAfter(endDate); date = date.plusDays(1)) {
                if (isWeekend(date)) {
                    continue;
                }
                totalInserted += syncSingleDate(date, stockByTicker);
            }

            if (totalInserted > 0 || "startup".equalsIgnoreCase(trigger)) {
                stockMetricsRefreshService.refreshAllForLatestOhlc(trigger);
            }

            log.info("OHLC sync ({}) completed. Inserted {} rows from {} to {}.", trigger, totalInserted, startDate, endDate);
        } finally {
            running.set(false);
        }
    }

    private void startBackgroundRefreshLoop() {
        if (!refreshLoopStarted.compareAndSet(false, true)) {
            return;
        }

        refreshExecutor.scheduleWithFixedDelay(() -> {
            try {
                syncMissingData("background");
            } catch (Exception ex) {
                log.error("Unexpected failure during background OHLC sync.", ex);
            }
        }, refreshInitialDelayMinutes, refreshIntervalMinutes, TimeUnit.MINUTES);

        log.info("Started background OHLC refresh loop with initial delay {} minute(s) and interval {} minute(s).",
                refreshInitialDelayMinutes, refreshIntervalMinutes);
    }

    private void ensureApiKeyConfigured() {
        if (apiKey == null || apiKey.isBlank()) {
            throw new IllegalStateException("massive.api.key is required for OHLC sync");
        }
    }

    @PreDestroy
    public void shutdown() {
        refreshExecutor.shutdownNow();
    }

    private int syncSingleDate(LocalDate date, Map<String, Stock> stockByTicker) {
        JsonNode response;
        try {
            response = restClient.get()
                    .uri(buildGroupedDailyPath(date))
                    .retrieve()
                    .body(JsonNode.class);
        } catch (HttpClientErrorException.NotFound ex) {
            log.debug("No grouped OHLC data for {}.", date);
            return 0;
        }

        if (response == null) {
            throw new IllegalStateException("Massive API returned empty response for grouped OHLC endpoint on " + date);
        }

        JsonNode resultsNode = response.path("results");
        if (!resultsNode.isArray()) {
            return 0;
        }

        boolean adjustedResponse = response.path("adjusted").asBoolean(adjusted);
        Set<Long> existingStockIds = new HashSet<>(stockMarketDataRepository.findStockIdsByTradingDate(date));
        List<StockMarketData> rows = new java.util.ArrayList<>();

        for (JsonNode node : resultsNode) {
            JsonNode tickerNode = node.get("T");
            String ticker = normalize(text(tickerNode == null || tickerNode.isNull() ? null : tickerNode.asText()));
            if (ticker == null) {
                continue;
            }

            Stock stock = stockByTicker.get(ticker);
            if (stock == null || stock.getStockId() == null || existingStockIds.contains(stock.getStockId())) {
                continue;
            }

            BigDecimal open = decimalOrNull(node.get("o"));
            BigDecimal high = decimalOrNull(node.get("h"));
            BigDecimal low = decimalOrNull(node.get("l"));
            BigDecimal close = decimalOrNull(node.get("c"));
            if (open == null || high == null || low == null || close == null) {
                continue;
            }

            StockMarketData row = new StockMarketData();
            row.setStock(stock);
            row.setTradingDate(date);
            row.setOpenPrice(open);
            row.setHighPrice(high);
            row.setLowPrice(low);
            row.setClosePrice(close);
            row.setVolume(longOrZero(node.get("v")));
            row.setVwap(decimalOrNull(node.get("vw")));
            row.setOtc(node.path("otc").asBoolean(false));
            row.setAdjusted(adjustedResponse);
            rows.add(row);
            existingStockIds.add(stock.getStockId());
        }

        if (rows.isEmpty()) {
            return 0;
        }

        stockMarketDataRepository.saveAll(rows);
        log.info("Inserted {} OHLC rows for {}.", rows.size(), date);
        return rows.size();
    }

    private String buildGroupedDailyPath(LocalDate date) {
        return UriComponentsBuilder.fromPath("/v2/aggs/grouped/locale/us/market/stocks/{date}")
                .queryParam("adjusted", adjusted)
                .queryParam("include_otc", includeOtc)
                .queryParam("apiKey", apiKey)
                .buildAndExpand(date)
                .toUriString();
    }

    private boolean isWeekend(LocalDate date) {
        DayOfWeek day = date.getDayOfWeek();
        return day == DayOfWeek.SATURDAY || day == DayOfWeek.SUNDAY;
    }

    private BigDecimal decimalOrNull(JsonNode node) {
        if (node == null || node.isNull()) {
            return null;
        }
        return BigDecimal.valueOf(node.asDouble()).setScale(2, RoundingMode.HALF_UP);
    }

    private long longOrZero(JsonNode node) {
        if (node == null || node.isNull()) {
            return 0L;
        }
        return Math.round(node.asDouble());
    }

    private String text(String value) {
        if (value == null) {
            return null;
        }
        String trimmed = value.trim();
        return trimmed.isEmpty() ? null : trimmed;
    }

    private String normalize(String value) {
        String text = text(value);
        return text == null ? null : text.toUpperCase(Locale.ROOT);
    }
}

package com.tradepulseai.stockservice.service;

import com.tradepulseai.stockservice.model.Stock;
import com.tradepulseai.stockservice.model.StockMarketData;
import com.tradepulseai.stockservice.repository.StockMarketDataRepository;
import com.tradepulseai.stockservice.repository.StockRepository;
import jakarta.annotation.PreDestroy;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.ApplicationArguments;
import org.springframework.boot.ApplicationRunner;
import org.springframework.core.annotation.Order;
import org.springframework.lang.NonNull;
import org.springframework.stereotype.Component;
import org.springframework.web.client.HttpClientErrorException;
import org.springframework.web.client.RestClient;
import org.springframework.web.util.UriComponentsBuilder;
import tools.jackson.databind.JsonNode;

import java.math.BigDecimal;
import java.math.RoundingMode;
import java.time.DayOfWeek;
import java.time.LocalDate;
import java.time.ZoneId;
import java.util.HashMap;
import java.util.HashSet;
import java.util.List;
import java.util.Locale;
import java.util.Map;
import java.util.Set;
import java.util.concurrent.atomic.AtomicBoolean;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;

@Component
@Order(3)
public class StockOhlcSyncService implements ApplicationRunner {

    private static final Logger log = LoggerFactory.getLogger(StockOhlcSyncService.class);

    private final StockRepository stockRepository;
    private final StockMarketDataRepository stockMarketDataRepository;
    private final StockMetricsRefreshService stockMetricsRefreshService;
    private final RestClient restClient;
    private final String apiKey;
    private final boolean syncOnStartup;
    private final boolean dailySyncEnabled;
    private final int yearsBack;
    private final long refreshInitialDelayMinutes;
    private final long refreshIntervalMinutes;
    private final boolean adjusted;
    private final boolean includeOtc;
    private final ZoneId syncZone;
    private final ScheduledExecutorService refreshExecutor;
    private final AtomicBoolean refreshLoopStarted = new AtomicBoolean(false);
    private final AtomicBoolean running = new AtomicBoolean(false);

    public StockOhlcSyncService(
            StockRepository stockRepository,
            StockMarketDataRepository stockMarketDataRepository,
            StockMetricsRefreshService stockMetricsRefreshService,
            @Value("${massive.api.base-url}") String apiBaseUrl,
            @Value("${massive.api.key:}") String apiKey,
            @Value("${massive.ohlc.sync-on-startup:true}") boolean syncOnStartup,
            @Value("${massive.ohlc.daily-sync-enabled:true}") boolean dailySyncEnabled,
            @Value("${massive.ohlc.years-back:3}") int yearsBack,
            @Value("${massive.ohlc.refresh-initial-delay-minutes:1}") long refreshInitialDelayMinutes,
            @Value("${massive.ohlc.refresh-interval-minutes:30}") long refreshIntervalMinutes,
            @Value("${massive.ohlc.adjusted:true}") boolean adjusted,
            @Value("${massive.ohlc.include-otc:false}") boolean includeOtc,
            @Value("${massive.ohlc.sync-zone:UTC}") String syncZone) {
        this.stockRepository = stockRepository;
        this.stockMarketDataRepository = stockMarketDataRepository;
        this.stockMetricsRefreshService = stockMetricsRefreshService;
        this.apiKey = apiKey;
        this.syncOnStartup = syncOnStartup;
        this.dailySyncEnabled = dailySyncEnabled;
        this.yearsBack = yearsBack;
        this.refreshInitialDelayMinutes = Math.max(1L, refreshInitialDelayMinutes);
        this.refreshIntervalMinutes = Math.max(1L, refreshIntervalMinutes);
        this.adjusted = adjusted;
        this.includeOtc = includeOtc;
        this.syncZone = ZoneId.of(syncZone);
        this.refreshExecutor = Executors.newSingleThreadScheduledExecutor(r -> {
            Thread thread = new Thread(r, "stock-ohlc-refresh");
            thread.setDaemon(true);
            return thread;
        });
        this.restClient = RestClient.builder()
                .baseUrl(apiBaseUrl)
                .build();
    }

    @Override
    public void run(@NonNull ApplicationArguments args) {
        if (syncOnStartup || dailySyncEnabled) {
            ensureApiKeyConfigured();
        }

        if (dailySyncEnabled) {
            startBackgroundRefreshLoop();
        }

        if (syncOnStartup) {
            syncMissingData("startup");
        }
    }

    private void syncMissingData(String trigger) {
        if (!running.compareAndSet(false, true)) {
            log.info("Skipping {} OHLC sync because another sync is already running.", trigger);
            return;
        }

        try {
            if (apiKey == null || apiKey.isBlank()) {
                throw new IllegalStateException("massive.api.key is required for OHLC sync");
            }

            List<Stock> stocks = stockRepository.findAllByOrderByStockIdAsc();
            if (stocks.isEmpty()) {
                log.info("Skipping {} OHLC sync because stocks table is empty.", trigger);
                return;
            }

            Map<String, Stock> stockByTicker = new HashMap<>();
            for (Stock stock : stocks) {
                String symbol = normalize(stock.getSymbol());
                if (symbol != null) {
                    stockByTicker.put(symbol, stock);
                }
            }

            LocalDate endDate = LocalDate.now(syncZone);
            LocalDate configuredStart = endDate.minusYears(yearsBack);
            LocalDate startDate = stockMarketDataRepository.findMaxTradingDate()
                    .map(date -> date.plusDays(1))
                    .orElse(configuredStart);

            if (startDate.isBefore(configuredStart)) {
                startDate = configuredStart;
            }

            if (startDate.isAfter(endDate)) {
                log.info("No missing OHLC dates to sync for trigger {}.", trigger);
                if ("startup".equalsIgnoreCase(trigger)) {
                    stockMetricsRefreshService.refreshAllForLatestOhlc(trigger);
                }
                return;
            }

            int totalInserted = 0;
            for (LocalDate date = startDate; !date.isAfter(endDate); date = date.plusDays(1)) {
                if (isWeekend(date)) {
                    continue;
                }
                totalInserted += syncSingleDate(date, stockByTicker);
            }

            if (totalInserted > 0 || "startup".equalsIgnoreCase(trigger)) {
                stockMetricsRefreshService.refreshAllForLatestOhlc(trigger);
            }

            log.info("OHLC sync ({}) completed. Inserted {} rows from {} to {}.", trigger, totalInserted, startDate, endDate);
        } finally {
            running.set(false);
        }
    }

    private void startBackgroundRefreshLoop() {
        if (!refreshLoopStarted.compareAndSet(false, true)) {
            return;
        }

        refreshExecutor.scheduleWithFixedDelay(() -> {
            try {
                syncMissingData("background");
            } catch (Exception ex) {
                log.error("Unexpected failure during background OHLC sync.", ex);
            }
        }, refreshInitialDelayMinutes, refreshIntervalMinutes, TimeUnit.MINUTES);

        log.info("Started background OHLC refresh loop with initial delay {} minute(s) and interval {} minute(s).",
                refreshInitialDelayMinutes, refreshIntervalMinutes);
    }

    private void ensureApiKeyConfigured() {
        if (apiKey == null || apiKey.isBlank()) {
            throw new IllegalStateException("massive.api.key is required for OHLC sync");
        }
    }

    @PreDestroy
    public void shutdown() {
        refreshExecutor.shutdownNow();
    }

    private int syncSingleDate(LocalDate date, Map<String, Stock> stockByTicker) {
        JsonNode response;
        try {
            response = restClient.get()
                    .uri(buildGroupedDailyPath(date))
                    .retrieve()
                    .body(JsonNode.class);
        } catch (HttpClientErrorException.NotFound ex) {
            log.debug("No grouped OHLC data for {}.", date);
            return 0;
        }

        if (response == null) {
            throw new IllegalStateException("Massive API returned empty response for grouped OHLC endpoint on " + date);
        }

        JsonNode resultsNode = response.path("results");
        if (!resultsNode.isArray()) {
            return 0;
        }

        Set<Long> existingStockIds = new HashSet<>(stockMarketDataRepository.findStockIdsByTradingDate(date));
        List<StockMarketData> rows = new java.util.ArrayList<>();

        for (JsonNode node : resultsNode) {
            JsonNode tickerNode = node.get("T");
            String ticker = normalize(text(tickerNode == null || tickerNode.isNull() ? null : tickerNode.asText()));
            if (ticker == null) {
                continue;
            }

            Stock stock = stockByTicker.get(ticker);
            if (stock == null || stock.getStockId() == null || existingStockIds.contains(stock.getStockId())) {
                continue;
            }

            BigDecimal open = decimalOrNull(node.get("o"));
            BigDecimal high = decimalOrNull(node.get("h"));
            BigDecimal low = decimalOrNull(node.get("l"));
            BigDecimal close = decimalOrNull(node.get("c"));
            if (open == null || high == null || low == null || close == null) {
                continue;
            }

            StockMarketData row = new StockMarketData();
            row.setStock(stock);
            row.setTradingDate(date);
            row.setOpenPrice(open);
            row.setHighPrice(high);
            row.setLowPrice(low);
            row.setClosePrice(close);
            row.setVolume(longOrZero(node.get("v")));
            row.setVwap(decimalOrNull(node.get("vw")));
            rows.add(row);
            existingStockIds.add(stock.getStockId());
        }

        if (rows.isEmpty()) {
            return 0;
        }

        stockMarketDataRepository.saveAll(rows);
        log.info("Inserted {} OHLC rows for {}.", rows.size(), date);
        return rows.size();
    }

    private String buildGroupedDailyPath(LocalDate date) {
        return UriComponentsBuilder.fromPath("/v2/aggs/grouped/locale/us/market/stocks/{date}")
                .queryParam("adjusted", adjusted)
                .queryParam("include_otc", includeOtc)
                .queryParam("apiKey", apiKey)
                .buildAndExpand(date)
                .toUriString();
    }

    private boolean isWeekend(LocalDate date) {
        DayOfWeek day = date.getDayOfWeek();
        return day == DayOfWeek.SATURDAY || day == DayOfWeek.SUNDAY;
    }

    private BigDecimal decimalOrNull(JsonNode node) {
        if (node == null || node.isNull()) {
            return null;
        }
        return BigDecimal.valueOf(node.asDouble()).setScale(2, RoundingMode.HALF_UP);
    }

    private long longOrZero(JsonNode node) {
        if (node == null || node.isNull()) {
            return 0L;
        }
        return Math.round(node.asDouble());
    }

    private String text(String value) {
        if (value == null) {
            return null;
        }
        String trimmed = value.trim();
        return trimmed.isEmpty() ? null : trimmed;
    }

    private String normalize(String value) {
        String text = text(value);
        return text == null ? null : text.toUpperCase(Locale.ROOT);
    }
}

-- Add compact daily news text for analytics UI and remove unused OHLC columns.
ALTER TABLE stock_daily_ohlc ADD COLUMN IF NOT EXISTS daily_news TEXT;
-- These columns are not used by the current frontend or ML pipeline. ALTER TABLE stock_daily_ohlc DROP COLUMN IF EXISTS is_otc, DROP COLUMN IF EXISTS adjusted;

-- Add pre-computed ML features to stock_daily_ohlc so the model
-- reads stored values instead of recomputing them at training time.

ALTER TABLE stock_daily_ohlc
    ADD COLUMN IF NOT EXISTS return_5d       NUMERIC(12, 4),
    ADD COLUMN IF NOT EXISTS momentum_20d    NUMERIC(12, 4),
    ADD COLUMN IF NOT EXISTS rsi_14          NUMERIC(8,  4),
    ADD COLUMN IF NOT EXISTS macd            NUMERIC(12, 4),
    ADD COLUMN IF NOT EXISTS macd_signal     NUMERIC(12, 4);

COMMENT ON COLUMN stock_daily_ohlc.return_5d    IS '5-day price return (%)';
COMMENT ON COLUMN stock_daily_ohlc.momentum_20d IS '20-day price momentum (%)';
COMMENT ON COLUMN stock_daily_ohlc.rsi_14       IS '14-period Relative Strength Index';
COMMENT ON COLUMN stock_daily_ohlc.macd         IS 'MACD line (EMA12 - EMA26)';
COMMENT ON COLUMN stock_daily_ohlc.macd_signal  IS 'MACD signal line (EMA9 of MACD)';

package com.tradepulseai.stockservice.service;

import com.tradepulseai.stockservice.dto.stock.StockInsightsResponseDTO;
import com.tradepulseai.stockservice.model.AllStocksLastValueCache;
import com.tradepulseai.stockservice.model.Stock;
import com.tradepulseai.stockservice.model.StockMarketData;
import com.tradepulseai.stockservice.repository.StockMarketDataRepository;
import com.tradepulseai.stockservice.repository.StockMetricsRepository;
import com.tradepulseai.stockservice.repository.StockRepository;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import org.mockito.InjectMocks;
import org.mockito.Mock;
import org.mockito.junit.jupiter.MockitoExtension;
import org.springframework.data.domain.Pageable;

import java.math.BigDecimal;
import java.time.Instant;
import java.time.LocalDate;
import java.util.List;
import java.util.Optional;

import static org.assertj.core.api.Assertions.assertThat;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.eq;
import static org.mockito.Mockito.when;

@ExtendWith(MockitoExtension.class)
class StockInsightsServiceTest {

    @Mock
    private StockRepository stockRepository;

    @Mock
    private StockMarketDataRepository stockMarketDataRepository;

    @Mock
    private StockMetricsRepository stockMetricsRepository;

    @Mock
    private AllStocksLastValueCacheService allStocksLastValueCacheService;

    @InjectMocks
    private StockInsightsService stockInsightsService;

    @Test
    void currentPerformanceUsesRealtimeCacheWhenAvailable() {
        Long stockId = 1L;
        Stock stock = stock(stockId);

        StockMarketData previousDay = marketData(LocalDate.of(2026, 6, 17), "100.00", 900_000L);
        StockMarketData latestDay = marketData(LocalDate.of(2026, 6, 18), "102.00", 1_000_000L);

        // Realtime cache has live intraday price
        AllStocksLastValueCache realtime = new AllStocksLastValueCache();
        realtime.setCachedClose(BigDecimal.valueOf(103.50));
        realtime.setCachedChangePercent(BigDecimal.valueOf(1.47));
        realtime.setAggregateUpdatedAt(Instant.parse("2026-06-19T14:30:00Z"));

        when(stockRepository.findById(stockId)).thenReturn(Optional.of(stock));
        when(stockRepository.findBySymbol("SPY")).thenReturn(Optional.empty());
        when(stockMetricsRepository.findById(stockId)).thenReturn(Optional.empty());
        when(stockMarketDataRepository.findRecentByStockId(eq(stockId), any(Pageable.class)))
                .thenReturn(List.of(latestDay, previousDay));
        when(allStocksLastValueCacheService.getCacheEntryByStockId(stockId)).thenReturn(realtime);

        StockInsightsResponseDTO response = stockInsightsService.getInsights(stockId);

        // Current price comes from realtime cache
        assertThat(response.currentPerformance().currentPrice()).isEqualTo(103.5d);
        // Previous close is latest daily OHLC close (yesterday's close relative to intraday price)
        assertThat(response.currentPerformance().previousClose()).isEqualTo(102.0d);
        // Daily change % comes from realtime cache
        assertThat(response.currentPerformance().dailyChangePercent()).isEqualTo(1.47d);
        // Volume uses daily OHLC — not realtime aggregate
        assertThat(response.volumeMetrics().latestTradingDayVolume()).isEqualTo(1_000_000L);
        assertThat(response.volumeMetrics().latestTradingDate()).isEqualTo("2026-06-18");
    }

    private static Stock stock(Long id) {
        Stock stock = new Stock();
        stock.setStockId(id);
        stock.setSymbol("AAPL");
        stock.setName("Apple Inc.");
        stock.setMarket("stocks");
        return stock;
    }

    private static StockMarketData marketData(LocalDate tradingDate, String closePrice, Long volume) {
        StockMarketData data = new StockMarketData();
        data.setTradingDate(tradingDate);
        data.setOpenPrice(new BigDecimal(closePrice));
        data.setHighPrice(new BigDecimal(closePrice));
        data.setLowPrice(new BigDecimal(closePrice));
        data.setClosePrice(new BigDecimal(closePrice));
        data.setVolume(volume);
        data.setAdjusted(true);
        data.setOtc(false);
        return data;
    }
}

